	(): PgEnumObjectColumnBuilderInitial<'', TValues>;
	<TName extends string>(name: TName): PgEnumObjectColumnBuilderInitial<TName, TValues>;
	<TName extends string>(name?: TName): PgEnumObjectColumnBuilderInitial<TName, TValues>;

	readonly enumName: string;
	readonly enumValues: string[];
