const TEXT_REGEXP = /^[\u0009\u0020-\u007e\u0080-\u00ff]*$/;
const TOKEN_REGEXP = /^[!#$%&'*+.^_`|~0-9A-Za-z-]+$/;

/**
 * RegExp to match chars that must be quoted-pair in RFC 9110 sec 5.6.4
 */
const QUOTE_REGEXP = /[\\"]/g;

/**
 * RegExp to match type in RFC 9110 sec 8.3.1
 *
 * media-type = type "/" subtype
 * type       = token
 * subtype    = token
 */
const TYPE_REGEXP =
  /^[!#$%&'*+.^_`|~0-9A-Za-z-]+\/[!#$%&'*+.^_`|~0-9A-Za-z-]+$/;

/**
 * Null object perf optimization. Faster than `Object.create(null)` and `{ __proto__: null }`.
 */
const NullObject = /* @__PURE__ */ (() => {
  const C = function () {};
  C.prototype = Object.create(null);
  return C;
})() as unknown as { new (): any };

/**
 * The content type object contains a type string and optional parameters.
 */
export interface ContentType {
  type: string;
  parameters: Record<string, string>;
}

/**
 * Format an object into a `Content-Type` header.
 */
export function format(obj: Partial<ContentType>): string {
  const { type, parameters } = obj;

  if (!type || !TYPE_REGEXP.test(type)) {
    throw new TypeError(`Invalid type: ${type}`);
  }

  let result = type;

  if (parameters) {
    for (const param of Object.keys(parameters)) {
      if (!TOKEN_REGEXP.test(param)) {
        throw new TypeError(`Invalid parameter name: ${param}`);
      }

      result += `; ${param}=${qstring(parameters[param])}`;
    }
  }

  return result;
}

/**
 * Options for parsing a `Content-Type` header.
 */
export interface ParseOptions {
  parameters?: boolean;
}

/**
 * Parse a `Content-Type` header.
 */
export function parse(header: string, options?: ParseOptions): ContentType {
  const len = header.length;
  let index = skipOWS(header, 0, len);

  const valueStart = index;
  index = skipValue(header, index, len);
  const valueEnd = trailingOWS(header, valueStart, index);
  const type = header.slice(valueStart, valueEnd).toLowerCase();
  const parameters =
    options?.parameters === false
      ? new NullObject()
      : parseParameters(header, index, len);

  return { type, parameters };
}

const SP = 32; // " "
const HTAB = 9; // "\t"
const SEMI = 59; // ";"
const EQ = 61; // "="
const DQUOTE = 34; // '"'
const BSLASH = 92; // "\\"

/**
 * Parses the parameters of a `Content-Type` header starting at the given index.
 */
function parseParameters(
  header: string,
  index: number,
  len: number,
): Record<string, string> {
  const parameters: Record<string, string> = new NullObject();

  parameter: while (index < len) {
    index = skipOWS(header, index + 1 /* Skip over ; */, len);

    const keyStart = index;

    while (index < len) {
      const code = header.charCodeAt(index);
      if (code === SEMI) continue parameter;

      if (code === EQ) {
        const keyEnd = trailingOWS(header, keyStart, index);
        const key = header.slice(keyStart, keyEnd).toLowerCase();

        index = skipOWS(header, index + 1, len);

        if (index < len && header.charCodeAt(index) === DQUOTE) {
          index++;

          let value = "";
          while (index < len) {
            const code = header.charCodeAt(index++);
            if (code === DQUOTE) {
              index = skipValue(header, index, len);
              if (parameters[key] === undefined) parameters[key] = value;
              break;
            }

            if (code === BSLASH && index < len) {
              value += header[index++];
              continue;
            }

            value += String.fromCharCode(code);
          }

          continue parameter;
        }

        const valueStart = index;
        index = skipValue(header, index, len);

        if (parameters[key] === undefined) {
          const valueEnd = trailingOWS(header, valueStart, index);
          parameters[key] = header.slice(valueStart, valueEnd);
        }

        continue parameter;
      }

      index++;
    }
  }

  return parameters;
}

/**
 * Skip over characters until a semicolon.
 */
function skipValue(str: string, index: number, len: number): number {
  while (index < len) {
    const char = str.charCodeAt(index);
    if (char === SEMI) break;
    index++;
  }
  return index;
}

/**
 * Skip optional whitespace (OWS) in an HTTP header value.
 *
 * OWS is defined in RFC 9110 sec 5.6.3 as SP (" ") or HTAB ("\t").
 */
function skipOWS(header: string, index: number, len: number): number {
  while (index < len) {
    const char = header.charCodeAt(index);
    if (char !== SP && char !== HTAB) break;
    index++;
  }
  return index;
}

/**
 * Trim optional whitespace (OWS) from the end of a substring.
 *
 * OWS is defined in RFC 9110 sec 5.6.3 as SP (" ") or HTAB ("\t").
 */
function trailingOWS(header: string, start: number, end: number): number {
  while (end > start) {
    const char = header.charCodeAt(end - 1);
    if (char !== SP && char !== HTAB) break;
    end--;
  }
  return end;
}

/**
 * Serialize a parameter value.
 */
function qstring(str: string): string {
  if (TOKEN_REGEXP.test(str)) return str;
  if (TEXT_REGEXP.test(str)) return `"${str.replace(QUOTE_REGEXP, "\\$&")}"`;

  throw new TypeError(`Invalid parameter value: ${str}`);
}

/*!
 * content-type
 * Copyright(c) 2015 Douglas Christopher Wilson
 * MIT Licensed
 */

const TEXT_REGEXP = /^[\u0009\u0020-\u007e\u0080-\u00ff]*$/;
const TOKEN_REGEXP = /^[!#$%&'*+.^_`|~0-9A-Za-z-]+$/;

/**
 * RegExp to match chars that must be quoted-pair in RFC 9110 sec 5.6.4
 */
const QUOTE_REGEXP = /[\\"]/g;

/**
 * RegExp to match type in RFC 9110 sec 8.3.1
 *
 * media-type = type "/" subtype
 * type       = token
 * subtype    = token
 */
const TYPE_REGEXP =
  /^[!#$%&'*+.^_`|~0-9A-Za-z-]+\/[!#$%&'*+.^_`|~0-9A-Za-z-]+$/;

/**
 * Null object perf optimization. Faster than `Object.create(null)` and `{ __proto__: null }`.
 */
const NullObject = /* @__PURE__ */ (() => {
  const C = function () {};
  C.prototype = Object.create(null);
  return C;
})() as unknown as { new (): any };

/**
 * The content type object contains a type string and optional parameters.
 */
export interface ContentType {
  type: string;
  parameters: Record<string, string>;
}

/**
 * Format an object into a `Content-Type` header.
 */
export function format(obj: Partial<ContentType>): string {
  const { type, parameters } = obj;

  if (!type || !TYPE_REGEXP.test(type)) {
    throw new TypeError(`Invalid type: ${type}`);
  }

  let result = type;

  if (parameters) {
    for (const param of Object.keys(parameters)) {
      if (!TOKEN_REGEXP.test(param)) {
        throw new TypeError(`Invalid parameter name: ${param}`);
      }

      result += `; ${param}=${qstring(parameters[param])}`;
    }
  }

  return result;
}

/**
 * Options for parsing a `Content-Type` header.
 */
export interface ParseOptions {
  parameters?: boolean;
}

/**
 * Parse a `Content-Type` header.
 */
export function parse(header: string, options?: ParseOptions): ContentType {
  const len = header.length;
  let index = skipOWS(header, 0, len);

  const valueStart = index;
  index = skipValue(header, index, len);
  const valueEnd = trailingOWS(header, valueStart, index);
  const type = header.slice(valueStart, valueEnd).toLowerCase();
  const parameters =
    options?.parameters === false
      ? new NullObject()
      : parseParameters(header, index, len);

  return { type, parameters };
}

const SP = 32; // " "
const HTAB = 9; // "\t"
const SEMI = 59; // ";"
const EQ = 61; // "="
const DQUOTE = 34; // '"'
const BSLASH = 92; // "\\"

/**
 * Parses the parameters of a `Content-Type` header starting at the given index.
 */
function parseParameters(
  header: string,
  index: number,
  len: number,
): Record<string, string> {
  const parameters: Record<string, string> = new NullObject();

  parameter: while (index < len) {
    index = skipOWS(header, index + 1 /* Skip over ; */, len);

    const keyStart = index;

    while (index < len) {
      const code = header.charCodeAt(index);
      if (code === SEMI) continue parameter;

      if (code === EQ) {
        const keyEnd = trailingOWS(header, keyStart, index);
        const key = header.slice(keyStart, keyEnd).toLowerCase();

        index = skipOWS(header, index + 1, len);

        if (index < len && header.charCodeAt(index) === DQUOTE) {
          index++;

          let value = "";
          while (index < len) {
            const code = header.charCodeAt(index++);
            if (code === DQUOTE) {
              index = skipValue(header, index, len);
              if (parameters[key] === undefined) parameters[key] = value;
              break;
            }

            if (code === BSLASH && index < len) {
              value += header[index++];
              continue;
            }

            value += String.fromCharCode(code);
          }

          continue parameter;
        }

        const valueStart = index;
        index = skipValue(header, index, len);

        if (parameters[key] === undefined) {
          const valueEnd = trailingOWS(header, valueStart, index);
          parameters[key] = header.slice(valueStart, valueEnd);
        }

        continue parameter;
      }

      index++;
    }
  }

  return parameters;
}

/**
 * Skip over characters until a semicolon.
 */
function skipValue(str: string, index: number, len: number): number {
  while (index < len) {
    const char = str.charCodeAt(index);
    if (char === SEMI) break;
    index++;
  }
  return index;
}

/**
 * Skip optional whitespace (OWS) in an HTTP header value.
 *
 * OWS is defined in RFC 9110 sec 5.6.3 as SP (" ") or HTAB ("\t").
 */
function skipOWS(header: string, index: number, len: number): number {
  while (index < len) {
    const char = header.charCodeAt(index);
    if (char !== SP && char !== HTAB) break;
    index++;
  }
  return index;
}

/**
 * Trim optional whitespace (OWS) from the end of a substring.
 *
 * OWS is defined in RFC 9110 sec 5.6.3 as SP (" ") or HTAB ("\t").
 */
function trailingOWS(header: string, start: number, end: number): number {
  while (end > start) {
    const char = header.charCodeAt(end - 1);
    if (char !== SP && char !== HTAB) break;
    end--;
  }
  return end;
}

/**
 * Serialize a parameter value.
 */
function qstring(str: string): string {
  if (TOKEN_REGEXP.test(str)) return str;
  if (TEXT_REGEXP.test(str)) return `"${str.replace(QUOTE_REGEXP, "\\$&")}"`;

  throw new TypeError(`Invalid parameter value: ${str}`);
}

const DEFAULT_DELIMITER = "/";
const NOOP_VALUE = (value: string) => value;
const ID_START = /^[$_\p{ID_Start}]$/u;
const ID_CONTINUE = /^[$\u200c\u200d\p{ID_Continue}]$/u;
const ID = /^[$_\p{ID_Start}][$\u200c\u200d\p{ID_Continue}]*$/u;

/**
 * Encode a string into another string.
 */
export type Encode = (value: string) => string;

/**
 * Decode a string into another string.
 */
export type Decode = (value: string) => string;

export interface ParseOptions {
  /**
   * A function for encoding input strings.
   */
  encodePath?: Encode;
}

export interface PathToRegexpOptions {
  /**
   * Matches the path completely without trailing characters. (default: `true`)
   */
  end?: boolean;
  /**
   * Allows optional trailing delimiter to match. (default: `true`)
   */
  trailing?: boolean;
  /**
   * Match will be case sensitive. (default: `false`)
   */
  sensitive?: boolean;
  /**
   * The default delimiter for segments. (default: `'/'`)
   */
  delimiter?: string;
}

export interface MatchOptions extends PathToRegexpOptions {
  /**
   * Function for decoding strings for params, or `false` to disable entirely. (default: `decodeURIComponent`)
   */
  decode?: Decode | false;
}

export interface CompileOptions {
  /**
   * Function for encoding input strings for output into the path, or `false` to disable entirely. (default: `encodeURIComponent`)
   */
  encode?: Encode | false;
  /**
   * The default delimiter for segments. (default: `'/'`)
   */
  delimiter?: string;
}

/**
 * Escape text for stringify to path.
 */
function escapeText(str: string) {
  return str.replace(/[{}()\[\]+?!:*\\]/g, "\\$&");
}

/**
 * Escape a regular expression string.
 */
function escape(str: string) {
  return str.replace(/[.+*?^${}()[\]|/\\]/g, "\\$&");
}

/**
 * Plain text.
 */
export interface Text {
  type: "text";
  value: string;
}

/**
 * A parameter designed to match arbitrary text within a segment.
 */
export interface Parameter {
  type: "param";
  name: string;
}

/**
 * A wildcard parameter designed to match multiple segments.
 */
export interface Wildcard {
  type: "wildcard";
  name: string;
}

/**
 * A set of possible tokens to expand when matching.
 */
export interface Group {
  type: "group";
  tokens: Token[];
}

/**
 * A token that corresponds with a regexp capture.
 */
export type Key = Parameter | Wildcard;

/**
 * A sequence of `path-to-regexp` keys that match capturing groups.
 */
export type Keys = Array<Key>;

/**
 * A sequence of path match characters.
 */
export type Token = Text | Parameter | Wildcard | Group;

/**
 * Tokenized path instance.
 */
export class TokenData {
  constructor(
    public readonly tokens: Token[],
    public readonly originalPath?: string,
  ) {}
}

/**
 * ParseError is thrown when there is an error processing the path.
 */
export class PathError extends TypeError {
  constructor(
    message: string,
    public readonly originalPath: string | undefined,
  ) {
    let text = message;
    if (originalPath) text += `: ${originalPath}`;
    text += `; visit https://git.new/pathToRegexpError for info`;
    super(text);
  }
}

/**
 * Parse a string for the raw tokens.
 */
export function parse(str: string, options: ParseOptions = {}): TokenData {
  const { encodePath = NOOP_VALUE } = options;
  const chars = [...str];
  let index = 0;

  function consumeUntil(end: string): Token[] {
    const output: Token[] = [];
    let path = "";

    function writePath() {
      if (!path) return;
      output.push({
        type: "text",
        value: encodePath(path),
      });
      path = "";
    }

    while (index < chars.length) {
      const value = chars[index++];

      if (value === end) {
        writePath();
        return output;
      }

      if (value === "\\") {
        if (index === chars.length) {
          throw new PathError(`Unexpected end after \\ at index ${index}`, str);
        }

        path += chars[index++];
        continue;
      }

      if (value === ":" || value === "*") {
        const type = value === ":" ? "param" : "wildcard";
        let name = "";

        if (ID_START.test(chars[index])) {
          do {
            name += chars[index++];
          } while (ID_CONTINUE.test(chars[index]));
        } else if (chars[index] === '"') {
          let quoteStart = index;

          while (index < chars.length) {
            if (chars[++index] === '"') {
              index++;
              quoteStart = 0;
              break;
            }

            // Increment over escape characters.
            if (chars[index] === "\\") index++;

            name += chars[index];
          }

          if (quoteStart) {
            throw new PathError(
              `Unterminated quote at index ${quoteStart}`,
              str,
            );
          }
        }

        if (!name) {
          throw new PathError(`Missing parameter name at index ${index}`, str);
        }

        writePath();
        output.push({ type, name });
        continue;
      }

      if (value === "{") {
        writePath();
        output.push({
          type: "group",
          tokens: consumeUntil("}"),
        });
        continue;
      }

      if (
        value === "}" ||
        value === "(" ||
        value === ")" ||
        value === "[" ||
        value === "]" ||
        value === "+" ||
        value === "?" ||
        value === "!"
      ) {
        throw new PathError(`Unexpected ${value} at index ${index - 1}`, str);
      }

      path += value;
    }

    if (end) {
      throw new PathError(
        `Unexpected end at index ${index}, expected ${end}`,
        str,
      );
    }

    writePath();
    return output;
  }

  return new TokenData(consumeUntil(""), str);
}

/**
 * Compile a string to a template function for the path.
 */
export function compile<P extends ParamData = ParamData>(
  path: Path,
  options: CompileOptions & ParseOptions = {},
) {
  const { encode = encodeURIComponent, delimiter = DEFAULT_DELIMITER } =
    options;
  const data = typeof path === "object" ? path : parse(path, options);
  const fn = tokensToFunction(data.tokens, delimiter, encode);

  return function path(params: P = {} as P) {
    const missing: string[] = [];
    const path = fn(params, missing);

    if (missing.length) {
      throw new TypeError(`Missing parameters: ${missing.join(", ")}`);
    }

    return path;
  };
}

export type ParamData = Partial<Record<string, string | string[]>>;
export type PathFunction<P extends ParamData> = (data?: P) => string;

/**
 * Internal path builder function.
 */
type TokenEncoder = (data: ParamData, missing: string[]) => string;

function tokensToFunction(
  tokens: Token[],
  delimiter: string,
  encode: Encode | false,
): TokenEncoder {
  const encoders = tokens.map((token) =>
    tokenToFunction(token, delimiter, encode),
  );

  return (data: ParamData, missing: string[]) => {
    let result = "";

    for (const encoder of encoders) {
      result += encoder(data, missing);
    }

    return result;
  };
}

/**
 * Convert a single token into a path building function.
 */
function tokenToFunction(
  token: Token,
  delimiter: string,
  encode: Encode | false,
): TokenEncoder {
  if (token.type === "text") return () => token.value;

  if (token.type === "group") {
    const fn = tokensToFunction(token.tokens, delimiter, encode);

    return (data, missing) => {
      const len = missing.length;
      const value = fn(data, missing);
      if (missing.length === len) return value;

      missing.length = len; // Reset optional group.
      return "";
    };
  }

  const encodeValue = encode || NOOP_VALUE;

  if (token.type === "wildcard" && encode !== false) {
    return (data, missing) => {
      const value = data[token.name];
      if (value == null) {
        missing.push(token.name);
        return "";
      }

      if (!Array.isArray(value) || value.length === 0) {
        throw new TypeError(`Expected "${token.name}" to be a non-empty array`);
      }

      let result = "";

      for (let i = 0; i < value.length; i++) {
        if (typeof value[i] !== "string") {
          throw new TypeError(`Expected "${token.name}/${i}" to be a string`);
        }

        if (i > 0) result += delimiter;
        result += encodeValue(value[i]);
      }

      return result;
    };
  }

  return (data, missing) => {
    const value = data[token.name];
    if (value == null) {
      missing.push(token.name);
      return "";
    }

    if (typeof value !== "string") {
      throw new TypeError(`Expected "${token.name}" to be a string`);
    }

    return encodeValue(value);
  };
}

/**
 * A match result contains data about the path match.
 */
export interface MatchResult<P extends ParamData> {
  path: string;
  params: P;
}

/**
 * A match is either `false` (no match) or a match result.
 */
export type Match<P extends ParamData> = false | MatchResult<P>;

/**
 * The match function takes a string and returns whether it matched the path.
 */
export type MatchFunction<P extends ParamData> = (path: string) => Match<P>;

/**
 * Supported path types.
 */
export type Path = string | TokenData;

/**
 * Transform a path into a match function.
 */
export function match<P extends ParamData>(
  path: Path | Path[],
  options: MatchOptions & ParseOptions = {},
): MatchFunction<P> {
  const { decode = decodeURIComponent, delimiter = DEFAULT_DELIMITER } =
    options;
  const { regexp, keys } = pathToRegexp(path, options);

  const decoders = keys.map((key) => {
    if (decode === false) return NOOP_VALUE;
    if (key.type === "param") return decode;
    return (value: string) => value.split(delimiter).map(decode);
  });

  return function match(input: string) {
    const m = regexp.exec(input);
    if (!m) return false;

    const path = m[0];
    const params = Object.create(null);

    for (let i = 1; i < m.length; i++) {
      if (m[i] === undefined) continue;

      const key = keys[i - 1];
      const decoder = decoders[i - 1];
      params[key.name] = decoder(m[i]);
    }

    return { path, params };
  };
}

/**
 * Transform a path into a regular expression and capture keys.
 */
export function pathToRegexp(
  path: Path | Path[],
  options: PathToRegexpOptions & ParseOptions = {},
) {
  const {
    delimiter = DEFAULT_DELIMITER,
    end = true,
    sensitive = false,
    trailing = true,
  } = options;
  const keys: Keys = [];
  let source = "";
  let combinations = 0;

  function process(path: Path | Path[]) {
    if (Array.isArray(path)) {
      for (const p of path) process(p);
      return;
    }

    const data = typeof path === "object" ? path : parse(path, options);
    flatten(data.tokens, 0, [], (tokens) => {
      if (combinations >= 256) {
        throw new PathError("Too many path combinations", data.originalPath);
      }

      if (combinations > 0) source += "|";
      source += toRegExpSource(tokens, delimiter, keys, data.originalPath);
      combinations++;
    });
  }

  process(path);

  let pattern = `^(?:${source})`;
  if (trailing) pattern += "(?:" + escape(delimiter) + "$)?";
  pattern += end ? "$" : "(?=" + escape(delimiter) + "|$)";

  return { regexp: new RegExp(pattern, sensitive ? "" : "i"), keys };
}

/**
 * Generate a flat list of sequence tokens from the given tokens.
 */
function flatten(
  tokens: Token[],
  index: number,
  result: Exclude<Token, Group>[],
  callback: (result: Exclude<Token, Group>[]) => void,
): void {
  while (index < tokens.length) {
    const token = tokens[index++];

    if (token.type === "group") {
      const len = result.length;
      flatten(token.tokens, 0, result, (seq) =>
        flatten(tokens, index, seq, callback),
      );
      result.length = len;
      continue;
    }

    result.push(token);
  }

  callback(result);
}

/**
 * Transform a flat sequence of tokens into a regular expression.
 */
function toRegExpSource(
  tokens: Exclude<Token, Group>[],
  delimiter: string,
  keys: Keys,
  originalPath: string | undefined,
): string {
  let result = "";
  let backtrack = "";
  let wildcardBacktrack = "";
  let prevCaptureType: 0 | 1 | 2 = 0;
  let hasSegmentCapture = 0;
  let index = 0;

  function hasInSegment(index: number, type: Token["type"]) {
    while (index < tokens.length) {
      const token = tokens[index++];
      if (token.type === type) return true;
      if (token.type === "text") {
        if (token.value.includes(delimiter)) break;
      }
    }
    return false;
  }

  function peekText(index: number) {
    let result = "";
    while (index < tokens.length) {
      const token = tokens[index++];
      if (token.type !== "text") break;
      result += token.value;
    }
    return result;
  }

  while (index < tokens.length) {
    const token = tokens[index++];

    if (token.type === "text") {
      result += escape(token.value);
      backtrack += token.value;
      if (prevCaptureType === 2) wildcardBacktrack += token.value;
      if (token.value.includes(delimiter)) hasSegmentCapture = 0;
      continue;
    }

    if (token.type === "param" || token.type === "wildcard") {
      if (prevCaptureType && !backtrack) {
        throw new PathError(
          `Missing text before "${token.name}" ${token.type}`,
          originalPath,
        );
      }

      if (token.type === "param") {
        result +=
          hasSegmentCapture & 2 // Seen wildcard in segment.
            ? `(${negate(delimiter, backtrack)}+)`
            : hasInSegment(index, "wildcard") // See wildcard later in segment.
              ? `(${negate(delimiter, peekText(index))}+)`
              : hasSegmentCapture & 1 // Seen parameter in segment.
                ? `(${negate(delimiter, backtrack)}+|${escape(backtrack)})`
                : `(${negate(delimiter, "")}+)`;

        hasSegmentCapture |= prevCaptureType = 1;
      } else {
        result +=
          hasSegmentCapture & 2 // Seen wildcard in segment.
            ? `(${negate(backtrack, "")}+)`
            : wildcardBacktrack // No capture in segment, seen wildcard in path.
              ? `(${negate(wildcardBacktrack, "")}+|${negate(delimiter, "")}+)`
              : `([^]+)`;

        wildcardBacktrack = "";
        hasSegmentCapture |= prevCaptureType = 2;
      }

      keys.push(token);
      backtrack = "";
      continue;
    }

    throw new TypeError(`Unknown token type: ${(token as any).type}`);
  }

  return result;
}

/**
 * Block backtracking on previous text/delimiter.
 */
function negate(a: string, b: string): string {
  if (b.length > a.length) return negate(b, a); // Longest string first.

  if (a === b) b = ""; // Cleaner regex strings, no duplication.
  if (b.length > 1) return `(?:(?!${escape(a)}|${escape(b)})[^])`;
  if (a.length > 1) return `(?:(?!${escape(a)})[^${escape(b)}])`;
  return `[^${escape(a + b)}]`;
}

/**
 * Stringify an array of tokens into a path string.
 */
function stringifyTokens(tokens: Token[], index: number): string {
  let value = "";

  while (index < tokens.length) {
    const token = tokens[index++];

    if (token.type === "text") {
      value += escapeText(token.value);
      continue;
    }

    if (token.type === "group") {
      value += "{" + stringifyTokens(token.tokens, 0) + "}";
      continue;
    }

    if (token.type === "param") {
      value += ":" + stringifyName(token.name, tokens[index]);
      continue;
    }

    if (token.type === "wildcard") {
      value += "*" + stringifyName(token.name, tokens[index]);
      continue;
    }

    throw new TypeError(`Unknown token type: ${(token as any).type}`);
  }

  return value;
}

/**
 * Stringify token data into a path string.
 */
export function stringify(data: TokenData): string {
  return stringifyTokens(data.tokens, 0);
}

/**
 * Stringify a parameter name, escaping when it cannot be emitted directly.
 */
function stringifyName(name: string, next: Token | undefined): string {
  if (!ID.test(name)) return JSON.stringify(name);

  if (next?.type === "text" && ID_CONTINUE.test(next.value[0])) {
    return JSON.stringify(name);
  }

  return name;
}

import type { Request } from 'express';
import type { AuthUser } from '../core/auth/service';

export function assertAuth(req: Request): asserts req is Request & { user: AuthUser } {
  if (!req.user) throw new Error('Não autenticado.');
}

import type { Request, Response, NextFunction } from 'express';

export function sendSuccess(res: Response, data?: unknown, status = 200): void {
  res.status(status).json({ success: true, data: data ?? null });
}

export function sendError(res: Response, error: string, status = 400): void {
  res.status(status).json({ success: false, error });
}

export function responseEnvelope(_req: Request, res: Response, next: NextFunction): void {
  const originalJson = res.json.bind(res);
  res.json = function (body: unknown) {
    if (body && typeof body === 'object' && !Array.isArray(body) && 'success' in (body as Record<string, unknown>)) {
      return originalJson(body);
    }
    if (res.statusCode >= 400) {
      const msg = body && typeof body === 'object'
        ? ((body as Record<string, unknown>).error as string ?? (body as Record<string, unknown>).message as string ?? 'Erro')
        : String(body ?? 'Erro');
      return originalJson({ success: false, error: msg });
    }
    if (body === undefined || body === null) {
      return originalJson({ success: true });
    }
    if (Array.isArray(body)) {
      return originalJson({ success: true, data: body });
    }
    const obj = body as Record<string, unknown>;
    if ('error' in obj) {
      return originalJson({ success: false, error: obj.error ?? 'Erro', ...obj });
    }
    if ('ok' in obj && obj.ok === true) {
      const { ok, ...rest } = obj;
      const keys = Object.keys(rest);
      if (keys.length === 0) return originalJson({ success: true });
      return originalJson({ success: true, data: keys.length === 1 ? rest[keys[0]] : rest });
    }
    return originalJson({ success: true, data: body });
  };
  next();
}

