import { createHash, randomUUID } from 'node:crypto';
import fs from 'node:fs';
import path from 'node:path';
import { createGzip, createGunzip, gunzipSync } from 'node:zlib';
import { pipeline } from 'node:stream/promises';
import { getSqlite, closeDb } from '../database/connection';
import { getLicenseCredentials, machineId, validateLicense } from '../license/service';
import { canSaveToCloud } from '../license/plans';
import { getCloudServerUrl } from '../config/cloud';

/**
 * Backup local (KATSU_PLANO.md §8):
 * compacta o SQLite (gzip), calcula checksum sha256 e registra no histórico.
 * Destino configurável via setting `backup.dir`. Restauração validada por checksum.
 * Fase 6c: se houver licença configurada, o backup também sobe para o cloud/
 * (best-effort — falha de rede não compromete o backup local, que já aconteceu).
 */

function backupDir(): string {
  const row = getSqlite()
    .prepare("SELECT value FROM settings WHERE key = 'backup.dir' AND deleted_at IS NULL")
    .get() as { value: string | null } | undefined;
  const dir = row?.value || path.resolve(process.cwd(), 'storage', 'backups');
  fs.mkdirSync(dir, { recursive: true });
  return dir;
}

function sha256(buf: Buffer): string {
  return createHash('sha256').update(buf).digest('hex');
}

export interface BackupResult {
  id: number;
  filePath: string;
  sizeBytes: number;
  checksum: string;
}

export interface BackupSettings {
  frequencia: 'diario' | 'semanal' | 'mensal';
  hora: string; // 'HH:MM'
  diaSemana: number; // 0 (domingo) .. 6 (sábado), usado só se frequencia = 'semanal'
  diaMes: number; // 1..28, usado só se frequencia = 'mensal'
  retencao: number | null; // null/0 = sem limite (não apaga nada automaticamente)
}

/** Configurações de agendamento/retenção de backup, guardadas na tabela `settings` (chaves `backup.*`). */
export function getBackupSettings(): BackupSettings {
  const rows = getSqlite()
    .prepare("SELECT key, value FROM settings WHERE key LIKE 'backup.%' AND deleted_at IS NULL")
    .all() as { key: string; value: string | null }[];
  const map = Object.fromEntries(rows.map((r) => [r.key, r.value]));
  const frequencia = map['backup.frequencia'] === 'semanal' || map['backup.frequencia'] === 'mensal' ? map['backup.frequencia'] : 'diario';
  return {
    frequencia,
    hora: map['backup.hora'] || '23:00',
    diaSemana: map['backup.dia_semana'] != null ? Number(map['backup.dia_semana']) : 0,
    diaMes: map['backup.dia_mes'] != null ? Number(map['backup.dia_mes']) : 1,
    retencao: map['backup.retencao'] != null ? Number(map['backup.retencao']) : 4,
  };
}

export async function runBackup(trigger: 'manual' | 'agendado' = 'manual'): Promise<BackupResult> {
  const db = getSqlite();
  const stamp = new Date().toISOString().replace(/[:.]/g, '-');
  const tmpDb = path.join(backupDir(), `katsu-${stamp}.db`);
  const finalPath = `${tmpDb}.gz`;

  await db.backup(tmpDb); // cópia consistente mesmo com o banco em uso
  await pipeline(fs.createReadStream(tmpDb), createGzip(), fs.createWriteStream(finalPath));
  fs.unlinkSync(tmpDb);
  const stat = fs.statSync(finalPath);

  const compressedBuf = fs.readFileSync(finalPath);
  const checksum = sha256(compressedBuf);
  const backupUuid = randomUUID();
  const info = db
    .prepare(
      `INSERT INTO backups (file_path, size_bytes, checksum, trigger, uuid) VALUES (?, ?, ?, ?, ?)`,
    )
    .run(finalPath, compressedBuf.length, checksum, trigger, backupUuid);
  const id = Number(info.lastInsertRowid);

  if (getLicenseCredentials().companyUuid && canSaveToCloud(validateLicense().plan)) {
    try {
      await uploadBackupToCloud(id);
    } catch (e) {
      console.error('[backup] falha ao enviar backup à nuvem (mantém apenas local):', e);
    }
  }

  try {
    await enforceRetention();
  } catch (e) {
    console.error('[backup] falha ao aplicar retenção (mantém os backups como estão):', e);
  }

  return { id, filePath: finalPath, sizeBytes: compressedBuf.length, checksum };
}

/**
 * Apaga os backups mais antigos além do limite configurado em `backup.retencao`
 * (local e, se o plano permitir nuvem, a cópia lá também). Sem limite configurado
 * (0/vazio), não faz nada — é opt-in.
 */
export async function enforceRetention(): Promise<void> {
  const { retencao } = getBackupSettings();
  if (!retencao || retencao <= 0) return;
  const db = getSqlite();
  const excess = db
    .prepare('SELECT id, file_path, uuid, uploaded_at FROM backups ORDER BY id DESC LIMIT -1 OFFSET ?')
    .all(retencao) as { id: number; file_path: string; uuid: string; uploaded_at: string | null }[];
  const canCloud = getLicenseCredentials().companyUuid && canSaveToCloud(validateLicense().plan);
  for (const row of excess) {
    if (row.uploaded_at && canCloud) {
      try {
        await deleteCloudBackup(row.uuid);
      } catch (e) {
        console.error('[backup] falha ao excluir cópia antiga na nuvem (mantém a exclusão local):', e);
      }
    }
    try {
      if (fs.existsSync(row.file_path)) fs.unlinkSync(row.file_path);
    } catch {
      // arquivo já não existe — segue a exclusão do registro mesmo assim
    }
    db.prepare('DELETE FROM backups WHERE id = ?').run(row.id);
  }
}

/** Restaura um backup do histórico. Valida checksum antes de tocar no banco. */
export function restoreBackup(backupId: number): { ok: boolean; error?: string } {
  const db = getSqlite();
  const row = db.prepare('SELECT file_path, checksum FROM backups WHERE id = ?').get(backupId) as
    | { file_path: string; checksum: string }
    | undefined;
  if (!row) return { ok: false, error: 'Backup não encontrado.' };
  if (!fs.existsSync(row.file_path)) return { ok: false, error: 'Arquivo de backup não existe mais.' };

  const compressed = fs.readFileSync(row.file_path);
  if (sha256(compressed) !== row.checksum) {
    return { ok: false, error: 'Checksum inválido — arquivo corrompido, restauração abortada.' };
  }

  const data = gunzipSync(compressed);
  const dbPath = (db as unknown as { name: string }).name;
  closeDb();
  fs.writeFileSync(dbPath, data);
  getSqlite(); // reabre
  return { ok: true };
}

export function listBackups() {
  return getSqlite()
    .prepare(
      'SELECT id, file_path, size_bytes, checksum, trigger, status, uploaded_at, created_at FROM backups ORDER BY id DESC LIMIT 100',
    )
    .all();
}

/**
 * Exclui um backup local (arquivo + linha). Se ele já tiver sido enviado à nuvem
 * (`uploaded_at` preenchido), tenta apagar a cópia lá também — best-effort: falha de
 * rede não impede a exclusão local, que já é o efeito principal pedido pelo usuário.
 */
export async function deleteBackup(backupId: number): Promise<{ ok: boolean; error?: string }> {
  const row = getSqlite().prepare('SELECT file_path, uuid, uploaded_at FROM backups WHERE id = ?').get(backupId) as
    | { file_path: string; uuid: string; uploaded_at: string | null }
    | undefined;
  if (!row) return { ok: false, error: 'Backup não encontrado.' };

  if (row.uploaded_at) {
    try {
      await deleteCloudBackup(row.uuid);
    } catch (e) {
      console.error('[backup] falha ao excluir cópia na nuvem (mantém a exclusão local):', e);
    }
  }
  try {
    if (fs.existsSync(row.file_path)) fs.unlinkSync(row.file_path);
  } catch {
    // arquivo já não existe — segue a exclusão do registro mesmo assim
  }
  getSqlite().prepare('DELETE FROM backups WHERE id = ?').run(backupId);
  return { ok: true };
}

function cloudBaseUrl(): string | null {
  const url = getCloudServerUrl();
  return url ? url.replace(/\/$/, '') : null;
}

function cloudAuthHeaders(): Record<string, string> | null {
  const { companyUuid, licenseKey } = getLicenseCredentials();
  if (!companyUuid || !licenseKey) return null;
  return { 'X-Katsu-Company': companyUuid, 'X-Katsu-License-Key': licenseKey };
}

/** Envia um backup já gravado localmente para o cloud/. Não faz nada se não houver licença/URL configurados. */
export async function uploadBackupToCloud(backupId: number): Promise<void> {
  const base = cloudBaseUrl();
  const auth = cloudAuthHeaders();
  if (!base || !auth) return;

  const row = getSqlite().prepare('SELECT file_path, checksum, uuid FROM backups WHERE id = ?').get(backupId) as
    | { file_path: string; checksum: string; uuid: string }
    | undefined;
  if (!row) return;

  const res = await fetch(`${base}/api/backup/upload`, {
    method: 'POST',
    headers: {
      ...auth,
      'Content-Type': 'application/gzip',
      'X-Katsu-Backup-Uuid': row.uuid,
      'X-Katsu-Backup-Checksum': row.checksum,
      'X-Katsu-Machine-Id': machineId(),
    },
    body: fs.readFileSync(row.file_path),
  });
  if (!res.ok) throw new Error(`Upload de backup falhou: ${res.status} ${await res.text()}`);

  getSqlite().prepare("UPDATE backups SET uploaded_at = datetime('now') WHERE id = ?").run(backupId);
}

export interface CloudBackupInfo {
  uuid: string;
  machineId: string;
  checksum: string;
  sizeBytes: number;
  createdAt: string;
}

/** Lista os backups disponíveis na nuvem para a empresa desta licença. */
export async function listCloudBackups(): Promise<CloudBackupInfo[]> {
  const base = cloudBaseUrl();
  const auth = cloudAuthHeaders();
  if (!base || !auth) throw new Error('Licença/URL da nuvem não configurados.');
  const res = await fetch(`${base}/api/backup`, { headers: auth });
  if (!res.ok) throw new Error(`Falha ao listar backups da nuvem: ${res.status} ${await res.text()}`);
  return (await res.json()) as CloudBackupInfo[];
}

/** Exclui um backup da nuvem (usado tanto pela exclusão em cascata de `deleteBackup` quanto pela lista "Backups na nuvem"). */
export async function deleteCloudBackup(cloudUuid: string): Promise<void> {
  const base = cloudBaseUrl();
  const auth = cloudAuthHeaders();
  if (!base || !auth) return; // sem nuvem configurada, nada a fazer

  const res = await fetch(`${base}/api/backup/${cloudUuid}`, { method: 'DELETE', headers: auth });
  if (!res.ok && res.status !== 404) {
    throw new Error(`Falha ao excluir backup da nuvem: ${res.status} ${await res.text()}`);
  }
}

/**
 * Baixa um backup da nuvem e registra localmente (trigger 'nuvem') — pronto para ser
 * restaurado com `restoreBackup(id)`, sem duplicar a lógica de checksum-e-sobrescrita.
 */
export async function downloadCloudBackup(cloudUuid: string): Promise<BackupResult> {
  const base = cloudBaseUrl();
  const auth = cloudAuthHeaders();
  if (!base || !auth) throw new Error('Licença/URL da nuvem não configurados.');

  const res = await fetch(`${base}/api/backup/${cloudUuid}/download`, { headers: auth });
  if (!res.ok) throw new Error(`Falha ao baixar backup da nuvem: ${res.status} ${await res.text()}`);
  const expectedChecksum = res.headers.get('X-Katsu-Backup-Checksum');
  const compressed = Buffer.from(await res.arrayBuffer());
  const checksum = sha256(compressed);
  if (expectedChecksum && checksum !== expectedChecksum) {
    throw new Error('Checksum inválido — backup da nuvem corrompido, download rejeitado.');
  }

  const finalPath = path.join(backupDir(), `katsu-nuvem-${cloudUuid}.gz`);
  fs.writeFileSync(finalPath, compressed);

  const db = getSqlite();
  db.prepare(
    `INSERT INTO backups (file_path, size_bytes, checksum, trigger, uuid) VALUES (?, ?, ?, 'nuvem', ?)
     ON CONFLICT(uuid) DO UPDATE SET file_path = excluded.file_path, size_bytes = excluded.size_bytes, checksum = excluded.checksum`,
  ).run(finalPath, compressed.length, checksum, cloudUuid);
  const { id } = db.prepare('SELECT id FROM backups WHERE uuid = ?').get(cloudUuid) as { id: number };

  return { id, filePath: finalPath, sizeBytes: compressed.length, checksum };
}

/**
 * Já passou do horário configurado hoje, é um dia elegível pra frequência escolhida,
 * e ainda não rodou um backup agendado hoje? Não checa o minuto exato — assim, se o
 * app estiver fechado no horário configurado, o backup roda assim que for aberto de
 * novo (catch-up), em vez de simplesmente perder o dia.
 */
function isScheduledBackupDue(now: Date): boolean {
  const s = getBackupSettings();
  const [hh, mm] = s.hora.split(':').map((n) => Number(n));
  if (Number.isNaN(hh) || Number.isNaN(mm)) return false;
  if (now.getHours() * 60 + now.getMinutes() < hh * 60 + mm) return false;
  if (s.frequencia === 'semanal' && now.getDay() !== s.diaSemana) return false;
  if (s.frequencia === 'mensal' && now.getDate() !== s.diaMes) return false;
  const today = now.toISOString().slice(0, 10);
  const already = getSqlite()
    .prepare("SELECT 1 FROM backups WHERE trigger = 'agendado' AND date(created_at) = ?")
    .get(today);
  return !already;
}

/** Agendador de backup: horário/frequência configuráveis em `backup.*` (settings). */
export function startBackupScheduler(): NodeJS.Timeout {
  const check = async () => {
    if (!isScheduledBackupDue(new Date())) return;
    try {
      await runBackup('agendado');
      console.log('[backup] backup agendado concluído.');
    } catch (e) {
      console.error('[backup] falha no backup agendado:', e);
    }
  };
  check(); // catch-up: cobre o caso do app ter ficado fechado no horário configurado
  const timer = setInterval(check, 60_000);
  timer.unref(); // não impede o processo de encerrar
  return timer;
}

/**
 * Planos comerciais do Katsu. Trial e Prata não incluem atualização automática nem
 * salvamento em nuvem (sync/backup); Ouro e Diamante incluem os dois. `app.online` fica
 * reservado para uma futura versão web do Diamante — sem produto associado ainda.
 *
 * Diferente de `isModuleEntitled` (fail-open quando não configurado — feito para módulos
 * de negócio), aqui o padrão é liberar tudo que NÃO for explicitamente trial/prata: isso
 * evita quebrar empresas com `plan` livre/antigo que nunca passaram por este novo modelo.
 */

export const PLAN_TIERS = ['trial', 'prata', 'ouro', 'diamante'] as const;
export type PlanTier = (typeof PLAN_TIERS)[number];

export const PLAN_LABELS: Record<PlanTier, string> = {
  trial: 'Teste (15 dias)',
  prata: 'Prata',
  ouro: 'Ouro',
  diamante: 'Diamante',
};

const RESTRICTED_PLANS = new Set<string>(['trial', 'prata']);

export function canAutoUpdate(plan: string | null): boolean {
  return !plan || !RESTRICTED_PLANS.has(plan.toLowerCase());
}

export function canSaveToCloud(plan: string | null): boolean {
  return !plan || !RESTRICTED_PLANS.has(plan.toLowerCase());
}

export function planLabel(plan: string | null): string {
  return plan ? (PLAN_LABELS[plan as PlanTier] ?? plan) : '—';
}

import { Router } from 'express';
import { requirePermission } from '../permissions/middleware';
import { audit } from '../audit/service';
import { validateLicense, setLicense, getEntitledModules, type LicenseInfo } from './service';
import { canAutoUpdate, canSaveToCloud } from './plans';
import { runSync } from '../sync/engine';

const router = Router();

function licensePayload(info: LicenseInfo) {
  return {
    ...info,
    modules: getEntitledModules(),
    canAutoUpdate: canAutoUpdate(info.plan),
    canSaveToCloud: canSaveToCloud(info.plan),
  };
}

router.get('/', requirePermission('license.view'), (_req, res) => {
  res.json(licensePayload(validateLicense()));
});

/**
 * Versão enxuta, sem `license.view`: qualquer usuário logado precisa disso para a
 * faixa de trial / modal de bloqueio por vencimento (nav.ejs), não só quem administra
 * a licença. Protegida apenas pelo `requireAuth` já aplicado ao router em server.ts.
 */
router.get('/status', (_req, res) => {
  const info = validateLicense();
  res.json({
    status: info.status,
    plan: info.plan,
    daysRemaining: info.daysRemaining,
    message: info.message,
    supportPhone: info.supportPhone,
    supportEmail: info.supportEmail,
    canSaveToCloud: canSaveToCloud(info.plan),
  });
});

/**
 * Salvar já sincroniza na hora (Fase 6f): sem isso, os efeitos (plano/módulos
 * corretos, backups da nuvem disponíveis) só apareciam depois de um "Sincronizar
 * agora" manual — que ficava escondido até a página recarregar. `sync` no retorno
 * é best-effort: se a nuvem estiver fora do ar, a licença é salva do mesmo jeito.
 */
router.put('/', requirePermission('license.edit'), async (req, res) => {
  const { companyUuid, licenseKey, plan, validUntil } = req.body ?? {};
  if (!companyUuid || !licenseKey) {
    res.status(400).json({ error: 'Campos obrigatórios: companyUuid, licenseKey.' });
    return;
  }
  const before = validateLicense();
  setLicense(String(companyUuid), String(licenseKey), plan, validUntil);

  let sync: { pushed: number; pulled: number; skipped?: boolean } | null = null;
  let syncError: string | null = null;
  try {
    sync = await runSync(req);
  } catch (e) {
    syncError = (e as Error).message;
  }

  const after = validateLicense();
  audit(req, 'editar', 'license', 1, before, after);
  res.json({ ...licensePayload(after), sync, syncError });
});

export default router;

import type { Request } from 'express';
import { getSqlite } from '../database/connection';
import { audit } from '../audit/service';
import { machineId, refreshLicenseFromCloud, validateLicense } from '../license/service';
import { canSaveToCloud } from '../license/plans';
import { getSyncTables, getRecomputeHook } from './registry';
import {
  tableColumns,
  getUuidById,
  getIdByUuid,
  getRowByUuid,
  getRowById,
  foreignKeyTargets,
  anyExistingId,
} from './introspect';
import { pushBatch, pullBatch } from './client';
import type {
  RegisteredSyncTable,
  SyncChildSpec,
  OutgoingRecord,
  IncomingRecord,
} from './types';

const BATCH_SIZE = 200;
const ALWAYS_SKIP = new Set(['id', 'uuid', 'synced_at', 'origin_machine', 'updated_at', 'deleted_at', 'comment']);

class UnresolvedForeignKeyError extends Error {}

function db() {
  return getSqlite();
}

function nowIso(): string {
  return (db().prepare("SELECT datetime('now') AS now").get() as { now: string }).now;
}

function isLedger(spec: RegisteredSyncTable): boolean {
  return !!spec.ledgerFor;
}

/** Colunas FK efetivas: as declaradas + a coluna de vínculo com o pai, se for ledger. */
function effectiveForeignKeys(spec: RegisteredSyncTable): Record<string, string> {
  const fk = { ...(spec.foreignKeys ?? {}) };
  if (spec.ledgerFor) {
    fk[spec.ledgerFor.parentColumn] = spec.ledgerFor.parentTable;
    Object.assign(fk, spec.ledgerFor.foreignKeys ?? {});
  }
  return fk;
}

// ---------------------------------------------------------------------------
// Coletar linhas alteradas (push)
// ---------------------------------------------------------------------------

const DIRTY_BATCH_SIZE = 500;

function collectDirtyRows(spec: RegisteredSyncTable): Record<string, unknown>[] {
  if (isLedger(spec)) {
    return db().prepare(`SELECT * FROM ${spec.table} WHERE synced_at IS NULL LIMIT ?`).all(DIRTY_BATCH_SIZE) as Record<
      string,
      unknown
    >[];
  }
  return db()
    .prepare(`SELECT * FROM ${spec.table} WHERE synced_at IS NULL OR synced_at < updated_at LIMIT ?`)
    .all(DIRTY_BATCH_SIZE) as Record<string, unknown>[];
}

function buildChildPayload(child: SyncChildSpec, row: Record<string, unknown>): Record<string, unknown> {
  const out: Record<string, unknown> = {};
  for (const col of tableColumns(child.table).map((c) => c.name)) {
    if (col === 'id' || col === child.parentColumn || ALWAYS_SKIP.has(col)) continue;
    if (child.excludeColumns?.includes(col)) continue;
    out[col] = child.foreignKeys?.[col]
      ? getUuidById(child.foreignKeys[col], row[col] as number | null)
      : row[col];
  }
  return out;
}

function buildOutgoingPayload(spec: RegisteredSyncTable, row: Record<string, unknown>): Record<string, unknown> {
  const fk = effectiveForeignKeys(spec);
  const payload: Record<string, unknown> = {};
  for (const col of tableColumns(spec.table).map((c) => c.name)) {
    if (ALWAYS_SKIP.has(col) || spec.excludeColumns?.includes(col)) continue;
    payload[col] = fk[col] ? getUuidById(fk[col], row[col] as number | null) : row[col];
  }
  for (const child of spec.children ?? []) {
    const rows = db()
      .prepare(`SELECT * FROM ${child.table} WHERE ${child.parentColumn} = ?`)
      .all(row.id) as Record<string, unknown>[];
    payload[child.table] = rows.map((r) => buildChildPayload(child, r));
  }
  return payload;
}

/** Reúne todas as linhas "sujas" de todas as tabelas registradas, prontas para push. */
export function collectOutgoingBatch(): OutgoingRecord[] {
  const machine = machineId();
  const out: OutgoingRecord[] = [];
  for (const spec of getSyncTables()) {
    for (const row of collectDirtyRows(spec)) {
      out.push({
        entityType: spec.entityType,
        uuid: String(row.uuid),
        payload: buildOutgoingPayload(spec, row),
        updatedAt: String(row.updated_at ?? row.created_at),
        deletedAt: row.deleted_at != null ? String(row.deleted_at) : null,
        originMachine: machine,
      });
    }
  }
  return out;
}

function markSynced(records: OutgoingRecord[]): void {
  const byTable = new Map<string, string[]>();
  for (const spec of getSyncTables()) {
    const uuids = records.filter((r) => r.entityType === spec.entityType).map((r) => r.uuid);
    if (uuids.length) byTable.set(spec.table, uuids);
  }
  const ts = nowIso();
  for (const [table, uuids] of byTable) {
    const placeholders = uuids.map(() => '?').join(', ');
    db().prepare(`UPDATE ${table} SET synced_at = ? WHERE uuid IN (${placeholders})`).run(ts, ...uuids);
  }
}

// ---------------------------------------------------------------------------
// Aplicar linhas recebidas (pull)
// ---------------------------------------------------------------------------

/** Traduz o payload recebido em valores de coluna locais; lança se uma FK ainda não existe localmente. */
function payloadToRowValues(spec: RegisteredSyncTable, payload: Record<string, unknown>): Record<string, unknown> {
  const fk = effectiveForeignKeys(spec);
  const values: Record<string, unknown> = {};
  for (const col of tableColumns(spec.table).map((c) => c.name)) {
    if (ALWAYS_SKIP.has(col) || spec.excludeColumns?.includes(col)) continue;
    if (fk[col]) {
      const uuidValue = payload[col] as string | null;
      const localId = getIdByUuid(fk[col], uuidValue);
      if (uuidValue != null && localId == null) {
        throw new UnresolvedForeignKeyError(`FK não resolvida: ${spec.table}.${col} -> ${fk[col]}(${uuidValue})`);
      }
      values[col] = localId;
    } else {
      values[col] = payload[col] ?? null;
    }
  }
  return values;
}

function applyChildren(spec: RegisteredSyncTable, parentLocalId: number, payload: Record<string, unknown>): void {
  for (const child of spec.children ?? []) {
    const rows = (payload[child.table] as Record<string, unknown>[] | undefined) ?? [];
    db().prepare(`DELETE FROM ${child.table} WHERE ${child.parentColumn} = ?`).run(parentLocalId);
    if (!rows.length) continue;
    const cols = tableColumns(child.table)
      .map((c) => c.name)
      .filter((n) => n !== 'id' && n !== child.parentColumn && n !== 'comment' && !child.excludeColumns?.includes(n));
    const insertCols = [child.parentColumn, ...cols];
    const stmt = db().prepare(
      `INSERT INTO ${child.table} (${insertCols.join(', ')}) VALUES (${insertCols.map(() => '?').join(', ')})`,
    );
    for (const r of rows) {
      const values = cols.map((c) => {
        if (!child.foreignKeys?.[c]) return r[c] ?? null;
        const uuidValue = r[c] as string | null;
        const localId = getIdByUuid(child.foreignKeys[c], uuidValue);
        if (uuidValue != null && localId == null) {
          throw new UnresolvedForeignKeyError(
            `FK não resolvida (filho): ${child.table}.${c} -> ${child.foreignKeys[c]}(${uuidValue})`,
          );
        }
        return localId;
      });
      stmt.run(parentLocalId, ...values);
    }
  }
}

/**
 * Colunas derivadas (excludeColumns) ficam de fora do payload — mas se forem NOT NULL
 * sem DEFAULT no schema (ex.: stock_movements.balance_after), o INSERT precisa de um
 * placeholder. É seguro: o hook de recompute (ex.: recomputeStockForProducts) corrige
 * o valor real logo em seguida, antes de qualquer leitura.
 */
function placeholdersForExcluded(spec: RegisteredSyncTable): Record<string, unknown> {
  const fkTargets = foreignKeyTargets(spec.table);
  const values: Record<string, unknown> = {};
  for (const col of tableColumns(spec.table)) {
    if (!spec.excludeColumns?.includes(col.name) || !col.notNull || col.hasDefault) continue;
    const refTable = fkTargets.get(col.name);
    // FK real para tabela não sincronizada (ex.: users): usa qualquer id local existente
    // (toda instalação tem ao menos o admin seedado). Sem FK (ex.: balance_after): usa 0.
    values[col.name] = refTable ? anyExistingId(refTable) : 0;
  }
  return values;
}

function insertNewRow(spec: RegisteredSyncTable, rec: IncomingRecord): number {
  const values = { ...placeholdersForExcluded(spec), ...payloadToRowValues(spec, rec.payload) };
  const cols = Object.keys(values);
  const isLedgerTable = isLedger(spec);
  const controlCols = isLedgerTable ? ['uuid', 'synced_at', 'origin_machine'] : ['uuid', 'updated_at', 'deleted_at', 'synced_at', 'origin_machine'];
  const allCols = [...cols, ...controlCols];
  const info = db()
    .prepare(`INSERT INTO ${spec.table} (${allCols.join(', ')}) VALUES (${allCols.map(() => '?').join(', ')})`)
    .run(
      ...cols.map((c) => values[c]),
      rec.uuid,
      ...(isLedgerTable ? [] : [rec.updatedAt, rec.deletedAt]),
      nowIso(),
      rec.originMachine,
    );
  const localId = Number(info.lastInsertRowid);
  if (!isLedgerTable) applyChildren(spec, localId, rec.payload);
  return localId;
}

function updateRow(req: Request, spec: RegisteredSyncTable, local: Record<string, unknown>, rec: IncomingRecord): void {
  const localId = Number(local.id);
  const localUpdatedAt = String(local.updated_at);
  const localSyncedAt = local.synced_at != null ? String(local.synced_at) : null;
  const localWasDirty = localSyncedAt === null || localUpdatedAt > localSyncedAt;
  // Edição concorrente: o último autor local difere de quem escreveu o valor que está chegando.
  // Complementa `localWasDirty` — sozinho, `synced_at` não sobrevive a rodadas de sync já
  // confirmadas antes de o conflito real aparecer (a própria máquina já marcou seu push como
  // sincronizado antes de saber da edição concorrente de outra máquina).
  const localOrigin = local.origin_machine != null ? String(local.origin_machine) : null;
  const differentAuthor = localOrigin != null && localOrigin !== rec.originMachine;

  const incomingWins =
    rec.updatedAt > localUpdatedAt ||
    (rec.updatedAt === localUpdatedAt && rec.originMachine > String(local.origin_machine ?? ''));
  if (!incomingWins) return; // local vence; será enviado no próximo push

  if (localWasDirty || differentAuthor) {
    audit(req, 'sync.conflict', spec.table, localId, local, rec.payload);
  }
  const values = payloadToRowValues(spec, rec.payload);
  const cols = Object.keys(values);
  const sets = cols
    .map((c) => `${c} = ?`)
    .concat(['updated_at = ?', 'deleted_at = ?', 'synced_at = ?', 'origin_machine = ?'])
    .join(', ');
  db()
    .prepare(`UPDATE ${spec.table} SET ${sets} WHERE id = ?`)
    .run(...cols.map((c) => values[c]), rec.updatedAt, rec.deletedAt, nowIso(), rec.originMachine, localId);
  applyChildren(spec, localId, rec.payload);
}

type PendingRecompute = Map<string, Set<number>>;

function applyIncomingRecord(req: Request, spec: RegisteredSyncTable, rec: IncomingRecord, pending: PendingRecompute): number | null {
  if (isLedger(spec)) {
    const existing = getRowByUuid(spec.table, rec.uuid);
    if (existing) return null; // append-only: já aplicado
    const localId = insertNewRow(spec, rec);
    const hook = getRecomputeHook(spec.table);
    if (hook) {
      const inserted = getRowById(spec.table, localId)!;
      const parentLocalId = Number(inserted[spec.ledgerFor!.parentColumn]);
      if (!pending.has(spec.table)) pending.set(spec.table, new Set());
      pending.get(spec.table)!.add(parentLocalId);
    }
    return localId;
  }
  const local = getRowByUuid(spec.table, rec.uuid);
  if (!local) return insertNewRow(spec, rec);
  updateRow(req, spec, local, rec);
  return Number(local.id);
}

async function applyIncomingBatch(req: Request, records: IncomingRecord[]): Promise<void> {
  const byEntityType = new Map(getSyncTables().map((s) => [s.entityType, s]));
  const pending: PendingRecompute = new Map();
  let queue = records;
  const lastError = new Map<string, string>();
  for (let attempt = 0; attempt < 3 && queue.length; attempt++) {
    const next: IncomingRecord[] = [];
    for (const rec of queue) {
      const spec = byEntityType.get(rec.entityType);
      if (!spec) continue;
      try {
        applyIncomingRecord(req, spec, rec, pending);
      } catch (e) {
        if (e instanceof UnresolvedForeignKeyError) {
          next.push(rec);
          lastError.set(rec.uuid, e.message);
        } else {
          throw e;
        }
      }
    }
    queue = next;
  }
  for (const rec of queue) {
    audit(req, 'sync.unresolved_fk', rec.entityType, undefined, null, {
      uuid: rec.uuid,
      reason: lastError.get(rec.uuid),
    });
  }
  for (const [table, ids] of pending) {
    const hook = getRecomputeHook(table);
    if (hook) await hook([...ids]);
  }
}

// ---------------------------------------------------------------------------
// Orquestração
// ---------------------------------------------------------------------------

async function pushAll(): Promise<number> {
  const outgoing = collectOutgoingBatch();
  let count = 0;
  for (let i = 0; i < outgoing.length; i += BATCH_SIZE) {
    const batch = outgoing.slice(i, i + BATCH_SIZE);
    await pushBatch(machineId(), batch);
    markSynced(batch);
    count += batch.length;
  }
  return count;
}

async function pullAll(req: Request): Promise<number> {
  let cursor: string | null = null;
  let count = 0;
  do {
    const page = await pullBatch(cursor);
    await applyIncomingBatch(req, page.records);
    count += page.records.length;
    cursor = page.nextCursor;
  } while (cursor);
  return count;
}

export async function runSync(req: Request): Promise<{ pushed: number; pulled: number; skipped?: boolean }> {
  // Reconectar também confirma entitlement/validade (Fase 6b) — best-effort, não
  // interrompe o resto do sync se o cloud/ estiver fora do ar. Módulos são checados
  // dinamicamente por requisição (não só no boot), então o plano atualizado aqui já
  // reflete imediatamente no restante do app.
  await refreshLicenseFromCloud();
  if (!canSaveToCloud(validateLicense().plan)) {
    return { pushed: 0, pulled: 0, skipped: true };
  }
  const pushed = await pushAll();
  const pulled = await pullAll(req);
  return { pushed, pulled };
}

import { getSqlite } from '../database/connection';

export interface ColumnInfo {
  name: string;
  type: string;
  notNull: boolean;
  pk: boolean;
  hasDefault: boolean;
}

interface PragmaRow {
  name: string;
  type: string;
  notnull: number;
  pk: number;
  dflt_value: unknown;
}

/**
 * Introspecção genérica via `PRAGMA table_info`: um único caminho de código para as
 * tabelas de módulo (SQL cru) sem precisar tipar tudo em Drizzle. Nomes de tabela vêm
 * só de `SyncTableSpec` declarado em manifestos (config interna de confiança, nunca
 * de input do usuário) — interpolação direta é segura, mesmo padrão de `crud.ts`.
 */
const columnCache = new Map<string, ColumnInfo[]>();

export function tableColumns(table: string): ColumnInfo[] {
  if (columnCache.has(table)) return columnCache.get(table)!;
  const rows = getSqlite().prepare(`PRAGMA table_info(${table})`).all() as PragmaRow[];
  if (!rows.length) throw new Error(`Tabela não encontrada: ${table}`);
  const result = rows.map((r) => ({
    name: r.name,
    type: r.type,
    notNull: !!r.notnull,
    pk: !!r.pk,
    hasDefault: r.dflt_value != null,
  }));
  columnCache.set(table, result);
  return result;
}

export function getRowByUuid(table: string, uuid: string): Record<string, unknown> | undefined {
  return getSqlite().prepare(`SELECT * FROM ${table} WHERE uuid = ?`).get(uuid) as
    | Record<string, unknown>
    | undefined;
}

export function getRowById(table: string, id: number): Record<string, unknown> | undefined {
  return getSqlite().prepare(`SELECT * FROM ${table} WHERE id = ?`).get(id) as
    | Record<string, unknown>
    | undefined;
}

export function getUuidById(table: string, id: number | null): string | null {
  if (id == null) return null;
  const row = getSqlite().prepare(`SELECT uuid FROM ${table} WHERE id = ?`).get(id) as
    | { uuid: string }
    | undefined;
  return row?.uuid ?? null;
}

export function getIdByUuid(table: string, uuid: string | null): number | null {
  if (uuid == null) return null;
  const row = getSqlite().prepare(`SELECT id FROM ${table} WHERE uuid = ?`).get(uuid) as
    | { id: number }
    | undefined;
  return row?.id ?? null;
}

interface ForeignKeyListRow {
  from: string;
  table: string;
}

const fkCache = new Map<string, Map<string, string>>();

/** coluna -> tabela referenciada, via `PRAGMA foreign_key_list` (inclui FKs não declaradas no SyncTableSpec, ex.: `users`). */
export function foreignKeyTargets(table: string): Map<string, string> {
  if (fkCache.has(table)) return fkCache.get(table)!;
  const rows = getSqlite().prepare(`PRAGMA foreign_key_list(${table})`).all() as ForeignKeyListRow[];
  const result = new Map(rows.map((r) => [r.from, r.table]));
  fkCache.set(table, result);
  return result;
}

/** Qualquer id existente na tabela — usado só como placeholder de FK NOT NULL não sincronizada (ex.: cash_registers.opened_by). */
export function anyExistingId(table: string): number | null {
  const row = getSqlite().prepare(`SELECT id FROM ${table} LIMIT 1`).get() as { id: number } | undefined;
  return row?.id ?? null;
}

import { getLicenseCredentials } from '../license/service';
import { getCloudServerUrl } from '../config/cloud';
import type { OutgoingRecord, IncomingRecord } from './types';

export interface PullPage {
  records: IncomingRecord[];
  nextCursor: string | null;
}

function baseUrl(): string {
  const url = getCloudServerUrl();
  if (!url) throw new Error('Servidor de sincronização não configurado (veja Configurações → Licença).');
  return url.replace(/\/$/, '');
}

function authHeaders(): Record<string, string> {
  const { companyUuid, licenseKey } = getLicenseCredentials();
  if (!companyUuid || !licenseKey) {
    throw new Error('Licença não configurada (company_uuid/license_key ausentes) — configure em /api/license.');
  }
  return {
    'Content-Type': 'application/json',
    'X-Katsu-Company': companyUuid,
    'X-Katsu-License-Key': licenseKey,
  };
}

/** Envia um lote de registros alterados localmente para o cloud/ (idempotente). */
export async function pushBatch(machineId: string, batch: OutgoingRecord[]): Promise<void> {
  if (!batch.length) return;
  const res = await fetch(`${baseUrl()}/api/sync/push`, {
    method: 'POST',
    headers: authHeaders(),
    body: JSON.stringify({ machineId, batch }),
  });
  if (!res.ok) throw new Error(`Push de sync falhou: ${res.status} ${await res.text()}`);
}

/** Busca uma página de registros alterados por outras máquinas desde o cursor informado. */
export async function pullBatch(cursor: string | null): Promise<PullPage> {
  const qs = new URLSearchParams({ limit: '500', ...(cursor ? { cursor } : {}) });
  const res = await fetch(`${baseUrl()}/api/sync/pull?${qs.toString()}`, { headers: authHeaders() });
  if (!res.ok) throw new Error(`Pull de sync falhou: ${res.status} ${await res.text()}`);
  return (await res.json()) as PullPage;
}

