import type { Request, Response, NextFunction } from 'express';
import { audit } from '../audit/service';
import { hasCapability } from './service';

export function requireCapability(key: string) {
  return (req: Request, res: Response, next: NextFunction): void => {
    if (!hasCapability(key)) {
      audit(req, 'acesso_negado', 'capability', key);
      res.status(403).json({ error: `Recurso desativado: ${key}` });
      return;
    }
    next();
  };
}

import { randomUUID } from 'node:crypto';
import type { Request, Response } from 'express';
import { audit } from '../../../core/audit/service';
import { openComanda, addItem, voidItem, transfer, split, merge, closeComanda, cancelComanda } from '../comandas';
import { storeTableRepository } from '../repositories/StoreTableRepository';
import { comandaRepository, comandaItemRepository } from '../repositories/ComandaRepository';

export const comandasController = {
  listTables(_req: Request, res: Response) {
    res.json(storeTableRepository.findAll({ orderBy: 'sort_order' }));
  },

  listTableStatus(_req: Request, res: Response) {
    res.json(storeTableRepository.findAll({ orderBy: 'sort_order' }));
  },

  createTable(req: Request, res: Response) {
    const { label, sortOrder } = req.body ?? {};
    if (!label) { res.status(400).json({ error: 'label obrigatorio.' }); return; }
    const id = storeTableRepository.create({
      label: String(label).trim(),
      sort_order: sortOrder ?? 0,
      uuid: randomUUID(),
      origin_machine: req.headers['x-machine'] ?? null,
    });
    audit(req, 'criar_mesa', 'table', id);
    res.status(201).json({ id });
  },

  updateTable(req: Request, res: Response) {
    const id = Number(req.params.id);
    const existing = storeTableRepository.rawOne('SELECT id FROM store_tables WHERE id = ? AND deleted_at IS NULL', id);
    if (!existing) { res.status(404).json({ error: 'Mesa nao encontrada.' }); return; }
    const { label, sortOrder } = req.body ?? {};
    storeTableRepository.update(id, { label: label ?? null, sort_order: sortOrder ?? null });
    audit(req, 'editar_mesa', 'table', id);
    res.json({ ok: true });
  },

  deleteTable(req: Request, res: Response) {
    const id = Number(req.params.id);
    const existing = storeTableRepository.rawOne(
      "SELECT id, status FROM store_tables WHERE id = ? AND deleted_at IS NULL", id,
    ) as { id: number; status: string } | undefined;
    if (!existing) { res.status(404).json({ error: 'Mesa nao encontrada.' }); return; }
    if (existing.status !== 'livre') { res.status(400).json({ error: 'Mesa ocupada nao pode ser removida.' }); return; }
    storeTableRepository.softDelete(id);
    audit(req, 'remover_mesa', 'table', id);
    res.json({ ok: true });
  },

  listComandas(req: Request, res: Response) {
    const status = req.query.status ? String(req.query.status) : undefined;
    let sql = `SELECT c.*, t.label AS table_label
      FROM comandas c
      LEFT JOIN store_tables t ON t.id = c.table_id
      WHERE c.deleted_at IS NULL`;
    const params: unknown[] = [];
    if (status) { sql += ' AND c.status = ?'; params.push(status); }
    sql += ' ORDER BY c.id DESC';
    res.json(comandaRepository.raw(sql, ...params));
  },

  getComanda(req: Request, res: Response) {
    const id = Number(req.params.id);
    const comanda = comandaRepository.rawOne(
      `SELECT c.*, t.label AS table_label
       FROM comandas c
       LEFT JOIN store_tables t ON t.id = c.table_id
       WHERE c.id = ? AND c.deleted_at IS NULL`,
      id,
    );
    if (!comanda) { res.status(404).json({ error: 'Comanda nao encontrada.' }); return; }
    const items = comandaItemRepository.raw(
      "SELECT * FROM comanda_items WHERE comanda_id = ? AND deleted_at IS NULL AND voided_at IS NULL ORDER BY id",
      id,
    );
    res.json({ ...comanda, items });
  },

  openComandaAction(req: Request, res: Response) {
    const { tableId, customerId, notes } = req.body ?? {};
    const result = openComanda(req, { tableId, customerId, notes });
    if (!result.ok) { res.status(400).json(result); return; }
    res.status(201).json(result);
  },

  addItemAction(req: Request, res: Response) {
    const comandaId = Number(req.params.id);
    const { productId, qty, notes, lineGroupUuid } = req.body ?? {};
    if (!productId || !qty) { res.status(400).json({ error: 'productId e qty obrigatorios.' }); return; }
    const result = addItem(req, comandaId, { productId, qty, notes, lineGroupUuid });
    if (!result.ok) { res.status(400).json(result); return; }
    res.status(201).json(result);
  },

  voidItemAction(req: Request, res: Response) {
    const comandaId = Number(req.params.id);
    const itemId = Number(req.params.itemId);
    const result = voidItem(req, comandaId, itemId);
    if (!result.ok) { res.status(400).json(result); return; }
    res.json({ ok: true });
  },

  transferAction(req: Request, res: Response) {
    const comandaId = Number(req.params.id);
    const { tableId } = req.body ?? {};
    if (!tableId) { res.status(400).json({ error: 'tableId obrigatorio.' }); return; }
    const result = transfer(req, comandaId, tableId);
    if (!result.ok) { res.status(400).json(result); return; }
    res.json({ ok: true });
  },

  splitAction(req: Request, res: Response) {
    const comandaId = Number(req.params.id);
    const { itemIds } = req.body ?? {};
    if (!itemIds?.length) { res.status(400).json({ error: 'itemIds obrigatorio.' }); return; }
    const result = split(req, comandaId, itemIds);
    if (!result.ok) { res.status(400).json(result); return; }
    res.json(result);
  },

  mergeAction(req: Request, res: Response) {
    const comandaId = Number(req.params.id);
    const { sourceComandaId } = req.body ?? {};
    if (!sourceComandaId) { res.status(400).json({ error: 'sourceComandaId obrigatorio.' }); return; }
    const result = merge(req, comandaId, sourceComandaId);
    if (!result.ok) { res.status(400).json(result); return; }
    res.json({ ok: true });
  },

  closeComandaAction(req: Request, res: Response) {
    const comandaId = Number(req.params.id);
    const { payments, discountCents, surchargeCents, customerId } = req.body ?? {};
    if (!payments?.length) { res.status(400).json({ error: 'payments obrigatorio.' }); return; }
    const result = closeComanda(req, comandaId, { payments, discountCents, surchargeCents, customerId });
    if (!result.ok) { res.status(400).json(result); return; }
    res.json(result);
  },

  cancelComandaAction(req: Request, res: Response) {
    const comandaId = Number(req.params.id);
    const result = cancelComanda(req, comandaId);
    if (!result.ok) { res.status(400).json(result); return; }
    res.json({ ok: true });
  },
};

import { randomUUID } from 'node:crypto';
import type { Request } from 'express';
import { getService, hasService } from '../../core/services/registry';
import { audit } from '../../core/audit/service';
import type { CommercialPricingService } from '../commercial/setup';
import type { FoodserviceKitchenService } from '../foodservice/setup';
import type { StoreSalesService } from '../store/setup';
import type { SaleInput } from '../store/sales';
import { assertAuth } from '../../shared/auth';
import { comandaRepository, comandaItemRepository } from './repositories/ComandaRepository';
import { storeTableRepository } from './repositories/StoreTableRepository';

interface OpenComandaParams { tableId?: number; customerId?: number; notes?: string }
interface AddItemParams { productId: number; qty: number; notes?: string; lineGroupUuid?: string }

interface ComandaRow {
  id: number; table_id: number | null; status: string; notes: string | null;
  customer_id: number | null; opened_by: number; sale_id?: number | null;
  closed_at?: string | null;
}

interface ComandaItemRow { id: number; productId: number; qty: number; notes: string | null; lineGroupUuid: string | null; unit_price_cents: number }

export function openComanda(req: Request, params: OpenComandaParams): { ok: true; id: number } | { ok: false; error: string } {
  assertAuth(req);
  if (params.tableId) {
    const table = storeTableRepository.rawOne(
      "SELECT id, status FROM store_tables WHERE id = ? AND deleted_at IS NULL",
      params.tableId,
    ) as { id: number; status: string } | undefined;
    if (!table) return { ok: false, error: 'Mesa nao encontrada.' };
    if (table.status !== 'livre') return { ok: false, error: 'Mesa ja esta ocupada.' };
  }
  const id = comandaRepository.create({
    table_id: params.tableId ?? null,
    customer_id: params.customerId ?? null,
    opened_by: req.user.id,
    notes: params.notes ?? null,
    uuid: randomUUID(),
    origin_machine: req.headers['x-machine'] ?? null,
  });
  if (params.tableId) {
    storeTableRepository.occupy(params.tableId);
  }
  audit(req, 'abrir_comanda', 'comanda', id, null, { tableId: params.tableId, customerId: params.customerId });
  return { ok: true, id };
}

export function addItem(req: Request, comandaId: number, params: AddItemParams): { ok: true; id: number } | { ok: false; error: string } {
  assertAuth(req);
  const comanda = comandaRepository.findOpen(comandaId) as ComandaRow | undefined;
  if (!comanda) return { ok: false, error: 'Comanda nao encontrada.' };
  if (comanda.status !== 'aberta') return { ok: false, error: 'Comanda nao esta aberta.' };
  const product = comandaRepository.rawOne(
    "SELECT id, name, price_cents, deleted_at FROM products WHERE id = ? AND deleted_at IS NULL",
    params.productId,
  ) as { id: number; name: string; price_cents: number; deleted_at: string | null } | undefined;
  if (!product) return { ok: false, error: 'Produto nao encontrado.' };
  const pricing = getService<CommercialPricingService>('commercial.pricing');
  const unitPriceCents = pricing.resolvePrice(product.id, params.qty, comanda.customer_id).unitCents;
  const itemId = comandaItemRepository.create({
    comanda_id: comandaId,
    product_id: product.id,
    product_name: product.name,
    qty: params.qty,
    unit_price_cents: unitPriceCents,
    notes: params.notes ?? null,
    line_group_uuid: params.lineGroupUuid ?? null,
    added_by: req.user.id,
    uuid: randomUUID(),
    origin_machine: req.headers['x-machine'] ?? null,
  });
  audit(req, 'adicionar_item_comanda', 'comanda_item', itemId, null, { comandaId, productId: product.id, qty: params.qty, unitPriceCents });
  if (hasService('foodservice.kitchen')) {
    try {
      const tableLabel = comanda.table_id
        ? (storeTableRepository.findByComandaTableId(comanda.table_id) as { label: string } | undefined)?.label
        : undefined;
      getService<FoodserviceKitchenService>('foodservice.kitchen').notifyOrder(req, {
        sourceType: 'comanda', sourceId: comandaId,
        tableLabel,
        items: [{ productId: product.id, name: product.name, qty: params.qty, notes: params.notes }],
      });
    } catch { /* best-effort */ }
  }
  return { ok: true, id: itemId };
}

export function voidItem(req: Request, comandaId: number, itemId: number): { ok: true } | { ok: false; error: string } {
  const item = comandaItemRepository.findInComanda(itemId, comandaId) as { id: number; voided_at: string | null } | undefined;
  if (!item) return { ok: false, error: 'Item nao encontrado.' };
  if (item.voided_at) return { ok: false, error: 'Item ja foi anulado.' };
  comandaItemRepository.void(itemId);
  audit(req, 'anular_item_comanda', 'comanda_item', itemId);
  return { ok: true };
}

export function transfer(req: Request, comandaId: number, targetTableId: number): { ok: true } | { ok: false; error: string } {
  const comanda = comandaRepository.rawOne(
    "SELECT id, table_id, status FROM comandas WHERE id = ? AND deleted_at IS NULL",
    comandaId,
  ) as { id: number; table_id: number | null; status: string } | undefined;
  if (!comanda) return { ok: false, error: 'Comanda nao encontrada.' };
  if (comanda.status !== 'aberta') return { ok: false, error: 'Comanda nao esta aberta.' };
  const target = storeTableRepository.rawOne(
    "SELECT id, status FROM store_tables WHERE id = ? AND deleted_at IS NULL",
    targetTableId,
  ) as { id: number; status: string } | undefined;
  if (!target) return { ok: false, error: 'Mesa destino nao encontrada.' };
  if (target.status !== 'livre') return { ok: false, error: 'Mesa destino esta ocupada.' };
  comandaRepository.transaction(() => {
    if (comanda.table_id) storeTableRepository.free(comanda.table_id);
    storeTableRepository.occupy(targetTableId);
    comandaRepository.transferTable(comandaId, targetTableId);
  });
  audit(req, 'transferir_comanda', 'comanda', comandaId, { tableIdAntes: comanda.table_id }, { tableIdDepois: targetTableId });
  return { ok: true };
}

export function split(req: Request, comandaId: number, itemIds: number[]): { ok: true; newComandaId: number } | { ok: false; error: string } {
  assertAuth(req);
  if (!itemIds?.length) return { ok: false, error: 'Nenhum item informado para dividir.' };
  const comanda = comandaRepository.findOpen(comandaId) as ComandaRow | undefined;
  if (!comanda || comanda.status !== 'aberta') return { ok: false, error: 'Comanda nao encontrada ou nao esta aberta.' };
  const validCount = comandaItemRepository.validateBelongToComanda(itemIds, comandaId);
  if (validCount !== itemIds.length) return { ok: false, error: 'Um ou mais itens nao encontrados ou ja anulados.' };
  let newComandaId: number;
  comandaRepository.transaction(() => {
    newComandaId = comandaRepository.create({
      table_id: null,
      customer_id: comanda.customer_id,
      opened_by: req.user.id,
      notes: comanda.notes,
      uuid: randomUUID(),
      origin_machine: req.headers['x-machine'] ?? null,
    });
    comandaItemRepository.moveToComanda(itemIds, newComandaId);
    audit(req, 'dividir_comanda', 'comanda', comandaId, null, { origem: comandaId, destino: newComandaId, itens: itemIds });
  });
  return { ok: true, newComandaId: newComandaId! };
}

export function merge(req: Request, targetComandaId: number, sourceComandaId: number): { ok: true } | { ok: false; error: string } {
  if (targetComandaId === sourceComandaId) return { ok: false, error: 'Nao e possivel unir uma comanda com ela mesma.' };
  const target = comandaRepository.findOpen(targetComandaId) as ComandaRow | undefined;
  if (!target || target.status !== 'aberta') return { ok: false, error: 'Comanda destino nao encontrada ou nao esta aberta.' };
  const source = comandaRepository.findOpen(sourceComandaId) as ComandaRow | undefined;
  if (!source || source.status !== 'aberta') return { ok: false, error: 'Comanda origem nao encontrada ou nao esta aberta.' };
  comandaRepository.transaction(() => {
    comandaItemRepository.mergeIntoComanda(sourceComandaId, targetComandaId);
    comandaRepository.cancel(sourceComandaId);
    if (source.table_id) storeTableRepository.free(source.table_id);
    audit(req, 'unir_comandas', 'comanda', sourceComandaId, null, { origem: sourceComandaId, destino: targetComandaId });
  });
  return { ok: true };
}

export function closeComanda(
  req: Request, comandaId: number,
  input: { payments: any[]; discountCents?: number; surchargeCents?: number; customerId?: number },
): { ok: true; saleId: number } | { ok: false; error: string } {
  const comanda = comandaRepository.findOpen(comandaId) as ComandaRow | undefined;
  if (!comanda) return { ok: false, error: 'Comanda nao encontrada.' };
  if (comanda.status !== 'aberta') return { ok: false, error: 'Comanda nao esta aberta.' };
  const items = comandaItemRepository.listActiveByComanda(comandaId) as unknown as ComandaItemRow[];
  if (!items.length) return { ok: false, error: 'Comanda sem itens para fechar.' };
  const saleInput: SaleInput = {
    items: items.map((i) => ({
      productId: i.productId,
      qty: i.qty,
      notes: i.notes ?? undefined,
      lineGroupUuid: i.lineGroupUuid ?? undefined,
      unitPriceCents: i.unit_price_cents,
    })),
    payments: input.payments,
    discountCents: input.discountCents,
    surchargeCents: input.surchargeCents,
    customerId: input.customerId ?? comanda.customer_id ?? undefined,
  };
  const storeSales = getService<StoreSalesService>('store.sales');
  const saleResult = storeSales.createSale(req, saleInput, { allowPriceOverride: true });
  if (!saleResult.ok) return { ok: false, error: saleResult.error };
  comandaRepository.close(comandaId, saleResult.id);
  if (comanda.table_id) storeTableRepository.free(comanda.table_id);
  audit(req, 'fechar_comanda', 'comanda', comandaId, null, { saleId: saleResult.id });
  return { ok: true, saleId: saleResult.id };
}

export function cancelComanda(req: Request, comandaId: number): { ok: true } | { ok: false; error: string } {
  const comanda = comandaRepository.findOpen(comandaId) as ComandaRow | undefined;
  if (!comanda) return { ok: false, error: 'Comanda nao encontrada.' };
  if (comanda.status !== 'aberta') return { ok: false, error: 'Comanda nao esta aberta.' };
  comandaRepository.transaction(() => {
    comandaRepository.cancel(comandaId);
    if (comanda.table_id) storeTableRepository.free(comanda.table_id);
  });
  audit(req, 'cancelar_comanda', 'comanda', comandaId);
  return { ok: true };
}

/**
 * Registro de serviços do Core (KATSU_PLANO.md §2):
 * "Um App não importa de outro App diretamente — comunicação entre Apps
 *  passa por eventos/serviços do Core."
 * Módulos registram serviços no boot (arquivo `setup` do manifesto) e
 * consomem serviços de outros módulos por nome, sem import direto.
 */
const services = new Map<string, unknown>();

export function registerService(name: string, impl: unknown): void {
  if (services.has(name)) throw new Error(`Serviço já registrado: ${name}`);
  services.set(name, impl);
}

/** Retorna o serviço ou lança erro claro (módulo dependente ausente/desabilitado). */
export function getService<T>(name: string): T {
  const svc = services.get(name);
  if (!svc) {
    throw new Error(
      `Serviço "${name}" não disponível. O módulo que o fornece está instalado e habilitado?`,
    );
  }
  return svc as T;
}

export function hasService(name: string): boolean {
  return services.has(name);
}

/** Uso em testes/reload. */
export function clearServices(): void {
  services.clear();
}

import { BaseRepository, type Row } from '../../../core/database/repository';

export class ComandaRepository extends BaseRepository {
  constructor() {
    super('comandas');
  }

  findOpen(id: number): Row | undefined {
    return this.rawOne(
      "SELECT id, table_id, customer_id, status, notes FROM comandas WHERE id = ? AND status = 'aberta' AND deleted_at IS NULL",
      id,
    );
  }

  close(id: number, saleId: number): void {
    this.rawRun(
      "UPDATE comandas SET status = 'fechada', sale_id = ?, closed_at = datetime('now'), updated_at = datetime('now') WHERE id = ?",
      saleId, id,
    );
  }

  cancel(id: number): void {
    this.rawRun(
      "UPDATE comandas SET status = 'cancelada', updated_at = datetime('now') WHERE id = ?",
      id,
    );
  }

  transferTable(id: number, targetTableId: number): void {
    this.rawRun(
      "UPDATE comandas SET table_id = ?, updated_at = datetime('now') WHERE id = ?",
      targetTableId, id,
    );
  }
}

export const comandaRepository = new ComandaRepository();

export class ComandaItemRepository extends BaseRepository {
  constructor() {
    super('comanda_items');
  }

  listActiveByComanda(comandaId: number): Row[] {
    return this.raw(
      `SELECT product_id AS productId, qty, notes, line_group_uuid AS lineGroupUuid, unit_price_cents
       FROM comanda_items WHERE comanda_id = ? AND deleted_at IS NULL AND voided_at IS NULL ORDER BY id`,
      comandaId,
    );
  }

  moveToComanda(ids: number[], targetComandaId: number): void {
    if (!ids.length) return;
    const ph = ids.map(() => '?').join(',');
    this.rawRun(
      `UPDATE comanda_items SET comanda_id = ?, updated_at = datetime('now') WHERE id IN (${ph})`,
      targetComandaId, ...ids,
    );
  }

  mergeIntoComanda(sourceComandaId: number, targetComandaId: number): void {
    this.rawRun(
      `UPDATE comanda_items SET comanda_id = ?, updated_at = datetime('now')
       WHERE comanda_id = ? AND deleted_at IS NULL AND voided_at IS NULL`,
      targetComandaId, sourceComandaId,
    );
  }

  findInComanda(itemId: number, comandaId: number): Row | undefined {
    return this.rawOne(
      "SELECT id, voided_at FROM comanda_items WHERE id = ? AND comanda_id = ? AND deleted_at IS NULL",
      itemId, comandaId,
    );
  }

  void(id: number): void {
    this.rawRun("UPDATE comanda_items SET voided_at = datetime('now'), updated_at = datetime('now') WHERE id = ?", id);
  }

  validateBelongToComanda(itemIds: number[], comandaId: number): number {
    if (!itemIds.length) return 0;
    const ph = itemIds.map(() => '?').join(',');
    const rows = this.raw(
      `SELECT id FROM comanda_items WHERE id IN (${ph}) AND comanda_id = ? AND deleted_at IS NULL AND voided_at IS NULL`,
      ...itemIds, comandaId,
    ) as { id: number }[];
    return rows.length;
  }
}

export const comandaItemRepository = new ComandaItemRepository();

import { BaseRepository, type Row } from '../../../core/database/repository';

export class StoreTableRepository extends BaseRepository {
  constructor() {
    super('store_tables');
  }

  findOpen(id: number): Row | undefined {
    return this.rawOne(
      "SELECT id, status FROM store_tables WHERE id = ? AND status = 'livre' AND deleted_at IS NULL",
      id,
    );
  }

  occupy(id: number): void {
    this.rawRun("UPDATE store_tables SET status = 'ocupada', updated_at = datetime('now') WHERE id = ?", id);
  }

  free(id: number): void {
    this.rawRun("UPDATE store_tables SET status = 'livre', updated_at = datetime('now') WHERE id = ?", id);
  }

  findByComandaTableId(id: number): Row | undefined {
    return this.rawOne("SELECT label FROM store_tables WHERE id = ?", id);
  }
}

export const storeTableRepository = new StoreTableRepository();

import { Router, type Request, type Response } from 'express';
import { assertAuth } from '../../shared/auth';

const router = Router();

function page(view: string, permission: string) {
  return (req: Request, res: Response) => {
    assertAuth(req);
    if (!req.user.permissions.has(permission)) return res.redirect('/');
    res.render(view, { user: req.user });
  };
}

router.get('/mesas', page('comandas-mesas', 'comandas.view'));
router.get('/mesas/:id', (req, res) => {
  assertAuth(req);
  if (!req.user.permissions.has('comandas.view')) return res.redirect('/');
  res.render('comandas-detalhe', { user: req.user, comandaId: Number(req.params.id) });
});

export default router;

import { registerService } from '../../core/services/registry';
import { registerRecomputeHook } from '../../core/sync/registry';
import { moveStock, moveStockRaw, listMovements, recomputeStockForProducts } from './stock';
import { resolvePrice, resolveMany } from './pricing';
import * as storeCredit from './storeCredit';
import * as loyalty from './loyalty';

/** Serviços que o módulo commercial oferece aos outros Apps (via Core). */
export interface CommercialStockService {
  move: typeof moveStock;
  /** Sem transação própria — use quando já estiver dentro de uma transação. */
  moveRaw: typeof moveStockRaw;
  listMovements: typeof listMovements;
}

export interface CommercialPricingService {
  resolvePrice: typeof resolvePrice;
  resolveMany: typeof resolveMany;
}

/** Crédito de troca (vale por devolução) — funções "Raw" não abrem transação própria. */
export interface CommercialStoreCreditService {
  grantRaw: typeof storeCredit.grant;
  redeemRaw: typeof storeCredit.redeem;
  reverseRaw: typeof storeCredit.reverse;
  balance: typeof storeCredit.getBalance;
  listMovements: typeof storeCredit.listCreditMovements;
}

/** Clube de fidelidade (pontos por real gasto) — funções "Raw" não abrem transação própria. */
export interface CommercialLoyaltyService {
  enabled: typeof loyalty.loyaltyEnabled;
  pointsForSaleCents: typeof loyalty.pointsForSaleCents;
  centsPerPoint: typeof loyalty.centsPerPoint;
  accrueRaw: typeof loyalty.accrue;
  redeemRaw: typeof loyalty.redeem;
  /** Estorna um RESGATE (devolve pontos gastos numa venda cancelada). */
  reverseRaw: typeof loyalty.reverse;
  /** Estorna um GANHO (remove pontos concedidos automaticamente por uma venda cancelada — pode ficar negativo). */
  reverseGrantRaw: typeof loyalty.reverseGrant;
  balance: typeof loyalty.getBalance;
  listMovements: typeof loyalty.listLoyaltyMovements;
}

export default function setup(): void {
  registerService('commercial.stock', { move: moveStock, moveRaw: moveStockRaw, listMovements } satisfies CommercialStockService);
  registerService('commercial.pricing', { resolvePrice, resolveMany } satisfies CommercialPricingService);
  registerService('commercial.storeCredit', {
    grantRaw: storeCredit.grant, redeemRaw: storeCredit.redeem, reverseRaw: storeCredit.reverse,
    balance: storeCredit.getBalance, listMovements: storeCredit.listCreditMovements,
  } satisfies CommercialStoreCreditService);
  registerService('commercial.loyalty', {
    enabled: loyalty.loyaltyEnabled, pointsForSaleCents: loyalty.pointsForSaleCents, centsPerPoint: loyalty.centsPerPoint,
    accrueRaw: loyalty.accrue, redeemRaw: loyalty.redeem, reverseRaw: loyalty.reverse, reverseGrantRaw: loyalty.reverseGrant,
    balance: loyalty.getBalance, listMovements: loyalty.listLoyaltyMovements,
  } satisfies CommercialLoyaltyService);
  registerRecomputeHook('stock_movements', recomputeStockForProducts);
  registerRecomputeHook('customer_credit_movements', storeCredit.recomputeStoreCreditForCustomers);
  registerRecomputeHook('loyalty_point_movements', loyalty.recomputeLoyaltyForCustomers);
}

import { randomUUID } from 'node:crypto';
import type { Request } from 'express';
import { audit } from '../../core/audit/service';
import { productRepository } from './repositories/ProductRepository';
import { stockMovementRepository } from './repositories/StockMovementRepository';

export type MovementType = 'entrada' | 'saida' | 'ajuste';

export function moveStockRaw(
  req: Request,
  productId: number,
  type: MovementType,
  qty: number,
  reason?: string,
  refEntity?: string,
  refId?: string | number,
  allowNegative = false,
): { ok: true; balance: number } | { ok: false; error: string } {
  if (!Number.isFinite(qty) || (type !== 'ajuste' && qty <= 0)) {
    return { ok: false, error: 'Quantidade inválida.' };
  }

  const product = productRepository.findByIdWithColumns(productId, 'id, name, track_stock, stock_qty') as
    | { id: number; name: string; track_stock: number; stock_qty: number } | undefined;
  if (!product) return { ok: false, error: 'Produto não encontrado.' };
  if (!product.track_stock) return { ok: false, error: 'Produto não controla estoque.' };

  const balance =
    type === 'entrada' ? product.stock_qty + qty
    : type === 'saida' ? product.stock_qty - qty
    : qty;

  if (balance < 0 && !allowNegative) {
    return { ok: false, error: `Estoque insuficiente: saldo ${product.stock_qty}, saída ${qty}.` };
  }

  productRepository.updateStock(productId, balance);
  productRepository.rawRun(
    `INSERT INTO stock_movements (product_id, type, qty, balance_after, reason, ref_entity, ref_id, user_id, uuid)
     VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)`,
    productId, type, qty, balance, reason ?? null, refEntity ?? null,
    refId != null ? String(refId) : null, req.user?.id ?? null, randomUUID(),
  );
  audit(req, `estoque_${type}`, 'product', productId, { saldo: product.stock_qty }, { saldo: balance, qty, reason });
  return { ok: true, balance };
}

export function moveStock(
  req: Request,
  productId: number,
  type: MovementType,
  qty: number,
  reason?: string,
  refEntity?: string,
  refId?: string | number,
): { ok: true; balance: number } | { ok: false; error: string } {
  let result: { ok: true; balance: number } | { ok: false; error: string } = { ok: false, error: 'Falha desconhecida.' };
  productRepository.transaction(() => {
    result = moveStockRaw(req, productId, type, qty, reason, refEntity, refId);
  });
  return result;
}

function yieldTick(): Promise<void> {
  return new Promise((resolve) => setImmediate(resolve));
}

export async function recomputeStockForProducts(productIds: number[]): Promise<void> {
  for (const productId of new Set(productIds)) {
    await yieldTick();
    const movements = stockMovementRepository.listAllByProduct(productId) as { id: number; type: MovementType; qty: number }[];
    let balance = 0;
    for (const m of movements) {
      balance = m.type === 'entrada' ? balance + m.qty : m.type === 'saida' ? balance - m.qty : m.qty;
      stockMovementRepository.updateBalance(m.id, balance);
    }
    productRepository.updateStock(productId, balance);
  }
}

export function listMovements(productId?: number, limit = 100) {
  return stockMovementRepository.list(productId, limit);
}

import { BaseRepository, type Row } from '../../../core/database/repository';

export interface ProductRow extends Row {
  id: number;
  name: string;
  description: string | null;
  sku: string | null;
  barcode: string | null;
  category_id: number | null;
  unit: string;
  price_cents: number;
  cost_cents: number;
  track_stock: number;
  stock_qty: number;
  min_stock: number;
  favorite: number;
  active: number;
  image_url: string | null;
  product_type: string;
  parent_product_id: number | null;
  visivel_cardapio: number;
}

const PRODUCT_COLS = `p.id, p.name, p.description, p.sku, p.barcode, p.category_id, c.name AS category,
  p.unit, p.price_cents, p.cost_cents, p.track_stock, p.stock_qty, p.min_stock, p.favorite, p.active,
  p.image_url, p.updated_at, p.product_type, p.parent_product_id, p.visivel_cardapio`;

export class ProductRepository extends BaseRepository<ProductRow> {
  constructor() {
    super('products');
  }

  findDetailed(id: number | string): Row | undefined {
    return this.rawOne(
      `SELECT ${PRODUCT_COLS} FROM products p LEFT JOIN categories c ON c.id = p.category_id
       WHERE p.id = ? AND p.deleted_at IS NULL`,
      id,
    );
  }

  search(query: string): Row[] {
    return this.raw(
      `SELECT ${PRODUCT_COLS} FROM products p LEFT JOIN categories c ON c.id = p.category_id
       WHERE p.deleted_at IS NULL
         AND NOT (p.product_type = 'variante' AND p.parent_product_id IS NULL)
         AND (p.name LIKE ? OR p.barcode = ? OR p.sku = ?)
       ORDER BY p.favorite DESC, p.name`,
      `%${query}%`, query, query,
    );
  }

  listTopLevel(): Row[] {
    return this.raw(
      `SELECT ${PRODUCT_COLS} FROM products p LEFT JOIN categories c ON c.id = p.category_id
       WHERE p.deleted_at IS NULL AND p.parent_product_id IS NULL
         AND NOT (p.product_type = 'variante' AND p.parent_product_id IS NULL)
       ORDER BY p.favorite DESC, p.name`,
    );
  }

  findByBarcode(barcode: string): Row | undefined {
    return this.rawOne(
      `SELECT ${PRODUCT_COLS} FROM products p LEFT JOIN categories c ON c.id = p.category_id
       WHERE p.barcode = ? AND p.deleted_at IS NULL
         AND NOT (p.product_type = 'variante' AND p.parent_product_id IS NULL)`,
      barcode,
    );
  }

  findVariants(parentId: number): Row[] {
    return this.raw(
      `SELECT ${PRODUCT_COLS},
              (SELECT json_group_array(json_object('attribute_id', pvv.attribute_id, 'attribute_name', pa.name, 'value_id', pvv.attribute_value_id, 'value', pav.value))
               FROM product_variant_values pvv
               LEFT JOIN product_attributes pa ON pa.id = pvv.attribute_id
               LEFT JOIN product_attribute_values pav ON pav.id = pvv.attribute_value_id
               WHERE pvv.product_id = p.id AND pvv.deleted_at IS NULL) AS variant_attrs
       FROM products p LEFT JOIN categories c ON c.id = p.category_id
       WHERE p.parent_product_id = ? AND p.deleted_at IS NULL
       ORDER BY p.name`,
      parentId,
    );
  }

  softDeleteWithVariants(id: number | string): void {
    this.transaction(() => {
      this.rawRun(
        `UPDATE products SET deleted_at = datetime('now'), updated_at = datetime('now') WHERE parent_product_id = ?`,
        id,
      );
      this.softDelete(id);
    });
  }

  setFavorite(id: number | string, favorite: boolean): void {
    this.update(id, { favorite: favorite ? 1 : 0 } as unknown as Partial<ProductRow>);
  }

  setCardapioOnline(id: number | string, visivel: boolean): void {
    this.update(id, { visivel_cardapio: visivel ? 1 : 0 } as unknown as Partial<ProductRow>);
  }

  updateStock(id: number | string, qty: number): void {
    this.rawRun("UPDATE products SET stock_qty = ?, updated_at = datetime('now') WHERE id = ?", qty, id);
  }

  updateCost(id: number | string, costCents: number): void {
    this.rawRun("UPDATE products SET cost_cents = ?, updated_at = datetime('now') WHERE id = ?", costCents, id);
  }

  generateAutoSku(id: number): void {
    this.rawRun("UPDATE products SET sku = ? WHERE id = ?", `P${String(id).padStart(6, '0')}`, id);
  }
}

