import { randomUUID } from 'node:crypto';
import type { Request } from 'express';
import { audit } from '../../core/audit/service';
import { assertAuth } from '../../shared/auth';
import { cashRegisterRepository, cashMovementRepository } from './repositories/CashRegisterRepository';
import { saleRepository } from '../store/repositories/SaleRepository';

export interface CashRegister {
  id: number;
  status: string;
  opening_cents: number;
  opened_at: string;
  opened_by: number;
}

export function currentRegister(): CashRegister | undefined {
  const row = cashRegisterRepository.findCurrent() as CashRegister | undefined;
  return row;
}

export interface CashRegisterDetail {
  id: number;
  status: string;
  opening_cents: number;
  opened_at: string;
  opened_by_name: string | null;
  closed_at: string | null;
  closed_by_name: string | null;
  expected_cents: number | null;
  counted_cents: number | null;
  difference_cents: number | null;
  notes: string | null;
  count_breakdown: Record<string, number> | null;
}

export function getRegisterById(registerId: number): CashRegisterDetail | undefined {
  return cashRegisterRepository.findDetail(registerId) as CashRegisterDetail | undefined;
}

export function registerTotals(registerId: number): { entradas: number; saidas: number } {
  return cashMovementRepository.totals(registerId);
}

export function expectedCents(registerId: number): number {
  const { entradas, saidas } = registerTotals(registerId);
  return entradas - saidas;
}

export function addMovement(
  req: Request,
  registerId: number,
  direction: 'entrada' | 'saida',
  type: 'abertura' | 'suprimento' | 'sangria' | 'venda' | 'recebimento' | 'pagamento',
  amountCents: number,
  description?: string,
  refEntity?: string,
  refId?: string | number,
): void {
  cashMovementRepository.create({
    register_id: registerId,
    direction,
    type,
    amount_cents: Math.round(amountCents),
    description: description ?? null,
    ref_entity: refEntity ?? null,
    ref_id: refId != null ? String(refId) : null,
    user_id: req.user?.id ?? null,
    uuid: randomUUID(),
  });
}

export function openRegister(req: Request, openingCents: number): { ok: true; id: number } | { ok: false; error: string } {
  assertAuth(req);
  if (currentRegister()) return { ok: false, error: 'Já existe um caixa aberto. Feche-o antes de abrir outro.' };
  if (!Number.isInteger(openingCents) || openingCents < 0) return { ok: false, error: 'Valor de abertura inválido.' };
  let id = 0;
  cashRegisterRepository.transaction(() => {
    id = cashRegisterRepository.create({
      opened_by: req.user.id,
      opening_cents: openingCents,
      uuid: randomUUID(),
    });
    if (openingCents > 0) addMovement(req, id, 'entrada', 'abertura', openingCents, 'Fundo de troco');
  });
  audit(req, 'caixa_abrir', 'cash_register', id, null, { openingCents });
  return { ok: true, id };
}

export function closeRegister(
  req: Request,
  countedCents: number,
  notes?: string,
  countBreakdown?: Record<string, number>,
): { ok: true; id: number; expected: number; counted: number; difference: number } | { ok: false; error: string } {
  assertAuth(req);
  const reg = currentRegister();
  if (!reg) return { ok: false, error: 'Nenhum caixa aberto.' };
  if (!Number.isInteger(countedCents) || countedCents < 0) return { ok: false, error: 'Valor contado inválido.' };

  const expected = expectedCents(reg.id);
  const difference = countedCents - expected;
  const breakdownJson = countBreakdown && Object.keys(countBreakdown).length ? JSON.stringify(countBreakdown) : null;
  cashRegisterRepository.close(reg.id, req.user.id, expected, countedCents, difference, notes ?? null, breakdownJson);
  audit(req, 'caixa_fechar', 'cash_register', reg.id, { expected }, { counted: countedCents, difference });
  return { ok: true, id: reg.id, expected, counted: countedCents, difference };
}

export function editClosedRegister(req: Request, registerId: number, updates: { countedCents?: number; notes?: string }):
  { ok: true; id: number; expected: number; counted: number; difference: number } | { ok: false; error: string } {
  assertAuth(req);
  const before = cashRegisterRepository.rawOne(
    'SELECT id, status, expected_cents, counted_cents, difference_cents FROM cash_registers WHERE id = ? AND deleted_at IS NULL',
    registerId,
  ) as { id: number; status: string; expected_cents: number; counted_cents: number; difference_cents: number } | undefined;
  if (!before) return { ok: false, error: 'Registro de caixa não encontrado.' };
  if (before.status !== 'fechado') return { ok: false, error: 'Apenas caixas fechados podem ser editados.' };

  const counted = updates.countedCents != null ? Math.round(updates.countedCents) : before.counted_cents;
  const difference = counted - before.expected_cents;

  cashRegisterRepository.editClosed(registerId, counted, difference, updates.notes ?? null, req.user.id);

  audit(req, 'caixa_editar', 'cash_register', registerId,
    { counted: before.counted_cents, difference: before.difference_cents },
    { counted, difference });
  return { ok: true, id: registerId, expected: before.expected_cents, counted, difference };
}

import { BaseRepository, type Row } from '../../../core/database/repository';

export class CashRegisterRepository extends BaseRepository {
  constructor() {
    super('cash_registers');
  }

  findCurrent(): Row | undefined {
    return this.rawOne(
      "SELECT * FROM cash_registers WHERE status = 'aberto' AND deleted_at IS NULL LIMIT 1",
    );
  }

  findDetail(id: number): Row | undefined {
    const row = this.rawOne(
      `SELECT r.id, r.status, r.opening_cents, r.opened_at, ou.username AS opened_by_name,
              r.closed_at, cu.username AS closed_by_name, r.expected_cents, r.counted_cents,
              r.difference_cents, r.notes, r.count_breakdown
       FROM cash_registers r
       LEFT JOIN users ou ON ou.id = r.opened_by
       LEFT JOIN users cu ON cu.id = r.closed_by
       WHERE r.id = ? AND r.deleted_at IS NULL`,
      id,
    );
    if (!row) return undefined;
    let countBreakdown: Record<string, number> | null = null;
    if (row.count_breakdown) {
      try { countBreakdown = JSON.parse(row.count_breakdown as string); }
      catch { countBreakdown = null; }
    }
    return { ...row, count_breakdown: countBreakdown };
  }

  listHistory(): Row[] {
    return this.raw(
      `SELECT r.id, r.status, r.opened_at, r.opening_cents, r.closed_at, r.expected_cents,
              r.counted_cents, r.difference_cents, r.edited_at, r.notes,
              uo.username AS opened_by, uc.username AS closed_by, ue.username AS edited_by_name
       FROM cash_registers r
       LEFT JOIN users uo ON uo.id = r.opened_by
       LEFT JOIN users uc ON uc.id = r.closed_by
       LEFT JOIN users ue ON ue.id = r.edited_by
       WHERE r.deleted_at IS NULL ORDER BY r.id DESC LIMIT 500`,
    );
  }

  close(id: number, closedBy: number, expected: number, counted: number, difference: number, notes: string | null, breakdownJson: string | null): void {
    this.rawRun(
      `UPDATE cash_registers SET status = 'fechado', closed_by = ?, closed_at = datetime('now'),
         expected_cents = ?, counted_cents = ?, difference_cents = ?, notes = COALESCE(?, notes),
         count_breakdown = ?, updated_at = datetime('now')
       WHERE id = ?`,
      closedBy, expected, counted, difference, notes, breakdownJson, id,
    );
  }

  editClosed(id: number, counted: number, difference: number, notes: string | null, userId: number): void {
    this.rawRun(
      `UPDATE cash_registers SET counted_cents = ?, difference_cents = ?, notes = COALESCE(?, notes),
         edited_at = datetime('now'), edited_by = ?, updated_at = datetime('now') WHERE id = ?`,
      counted, difference, notes, userId, id,
    );
  }
}

export const cashRegisterRepository = new CashRegisterRepository();

export class CashMovementRepository extends BaseRepository {
  constructor() {
    super('cash_movements');
  }

  listByRegister(registerId: number): Row[] {
    return this.raw(
      `SELECT m.id, m.direction, m.type, m.amount_cents, m.description, m.ref_entity, m.ref_id,
              u.username, m.created_at
       FROM cash_movements m LEFT JOIN users u ON u.id = m.user_id
       WHERE m.register_id = ? ORDER BY m.id DESC`,
      registerId,
    );
  }

  totals(registerId: number): { entradas: number; saidas: number } {
    return this.rawOne(
      `SELECT
         COALESCE(SUM(CASE WHEN direction = 'entrada' THEN amount_cents END), 0) AS entradas,
         COALESCE(SUM(CASE WHEN direction = 'saida' THEN amount_cents END), 0) AS saidas
       FROM cash_movements WHERE register_id = ?`,
      registerId,
    ) as { entradas: number; saidas: number };
  }

  cashflow(from: string, to: string): Row[] {
    return this.raw(
      `SELECT date(created_at) AS day,
              COALESCE(SUM(CASE WHEN direction = 'entrada' THEN amount_cents END), 0) AS entradas,
              COALESCE(SUM(CASE WHEN direction = 'saida' THEN amount_cents END), 0) AS saidas
       FROM cash_movements
       WHERE date(created_at) BETWEEN ? AND ?
       GROUP BY date(created_at) ORDER BY day`,
      from, to,
    );
  }
}

export const cashMovementRepository = new CashMovementRepository();

import { randomUUID } from 'node:crypto';
import type { Request } from 'express';
import { audit } from '../../core/audit/service';
import { receivableRepository } from './repositories/BillRepository';
import { agreementCompanyRepository, agreementChargeRepository } from './repositories/AgreementRepository';

export function periodKeyFor(date: Date = new Date()): string {
  return date.toISOString().slice(0, 7);
}

function dueDateForPeriod(periodKey: string, billingDay: number): string {
  const [year, month] = periodKey.split('-').map(Number);
  const lastDay = new Date(year, month, 0).getDate();
  const day = Math.min(billingDay, lastDay);
  return `${periodKey}-${String(day).padStart(2, '0')}`;
}

export function chargeAgreementRaw(saleId: number, agreementCompanyId: number, amountCents: number): number {
  return agreementChargeRepository.create({
    sale_id: saleId,
    agreement_company_id: agreementCompanyId,
    amount_cents: Math.round(amountCents),
    uuid: randomUUID(),
  });
}

export function pendingTotal(companyId: number): number {
  return agreementChargeRepository.pendingTotal(companyId);
}

export function generateInvoice(
  req: Request,
  companyId: number,
  periodKey?: string,
): { ok: true; receivableId: number; amountCents: number } | { ok: false; error: string } {
  const company = agreementCompanyRepository.rawOne(
    'SELECT id, name, billing_day FROM agreement_companies WHERE id = ? AND deleted_at IS NULL',
    companyId,
  ) as { id: number; name: string; billing_day: number } | undefined;
  if (!company) return { ok: false, error: 'Empresa conveniada não encontrada.' };

  const key = periodKey ?? periodKeyFor();
  const already = receivableRepository.findByAgreementAndPeriod(companyId, key);
  if (already) return { ok: false, error: `Já existe fatura gerada para o período ${key}.` };

  const amountCents = pendingTotal(companyId);
  if (amountCents <= 0) return { ok: false, error: 'Nenhuma cobrança pendente para este convênio.' };

  let receivableId = 0;
  agreementChargeRepository.transaction(() => {
    const id = receivableRepository.create({
      description: `Fatura convênio ${company.name} — ${key}`,
      amount_cents: amountCents,
      due_date: dueDateForPeriod(key, company.billing_day),
      agreement_company_id: companyId,
      period_key: key,
      uuid: randomUUID(),
    });
    receivableId = id;
    agreementChargeRepository.invoiceAll(companyId, id);
  });
  audit(req, 'convenio_fatura_gerar', 'agreement_company', companyId, null, { receivableId, amountCents, period: key });
  return { ok: true, receivableId, amountCents };
}

export function companiesDueForInvoice(today: Date = new Date()): { id: number; name: string; billingDay: number }[] {
  const key = periodKeyFor(today);
  const companies = agreementCompanyRepository.raw(
    'SELECT id, name, billing_day AS billingDay FROM agreement_companies WHERE active = 1 AND deleted_at IS NULL',
  ) as { id: number; name: string; billingDay: number }[];
  return companies.filter((c) => {
    if (today.getDate() < c.billingDay) return false;
    const already = receivableRepository.findByAgreementAndPeriod(c.id, key);
    if (already) return false;
    return pendingTotal(c.id) > 0;
  });
}

import { BaseRepository, type Row } from '../../../core/database/repository';

export class PayableRepository extends BaseRepository {
  constructor() {
    super('payables');
  }

  list(status?: string, partyId?: number): Row[] {
    const conditions = ['b.deleted_at IS NULL'];
    const params: unknown[] = [];
    if (status) { conditions.push('b.status = ?'); params.push(status); }
    if (partyId) { conditions.push('b.supplier_id = ?'); params.push(partyId); }
    const where = conditions.join(' AND ');
    return this.raw(
      `SELECT b.id, b.description, s.name AS party, b.amount_cents, b.issue_date, b.due_date, b.status,
              b.notes, b.paid_at AS settled_at, b.paid_cents AS settled_cents,
              spm.name AS settle_method_name,
              b.installment_group_id, b.installment_no, b.installment_count,
              b.dre_category_id, dc.label AS dre_category_label
       FROM payables b LEFT JOIN suppliers s ON s.id = b.supplier_id
            LEFT JOIN payment_methods spm ON spm.id = b.settle_payment_method_id
            LEFT JOIN dre_categories dc ON dc.id = b.dre_category_id
       WHERE ${where} ORDER BY b.due_date, b.id`,
      ...params,
    );
  }

  findDetail(id: number | string): Row | undefined {
    return this.rawOne(
      `SELECT b.id, b.description, b.supplier_id AS party_id, s.name AS party,
              b.amount_cents, b.issue_date, b.due_date, b.status, b.paid_at AS settled_at,
              b.paid_cents AS settled_cents, b.notes, b.updated_at,
              b.settle_payment_method_id, spm.name AS settle_method_name,
              b.installment_group_id, b.installment_no, b.installment_count,
              b.dre_category_id, dc.label AS dre_category_label
       FROM payables b LEFT JOIN suppliers s ON s.id = b.supplier_id
            LEFT JOIN payment_methods spm ON spm.id = b.settle_payment_method_id
            LEFT JOIN dre_categories dc ON dc.id = b.dre_category_id
       WHERE b.id = ? AND b.deleted_at IS NULL`,
      id,
    );
  }

  findNextInstallment(groupId: string, nextNo: number): Row | undefined {
    return this.rawOne(
      `SELECT id FROM payables WHERE installment_group_id = ? AND installment_no = ? AND status = 'aberta'`,
      groupId, nextNo,
    );
  }

  settle(id: number | string, status: string, dateCol: string, centsCol: string, paidCents: number, paymentMethodId: number | null): void {
    this.rawRun(
      `UPDATE payables SET status = ?, ${dateCol} = datetime('now'), ${centsCol} = ?, settle_payment_method_id = ?, updated_at = datetime('now') WHERE id = ?`,
      status, paidCents, paymentMethodId, id,
    );
  }
}

export const payableRepository = new PayableRepository();

export class ReceivableRepository extends BaseRepository {
  constructor() {
    super('receivables');
  }

  list(status?: string, partyId?: number, agreementCompanyId?: number): Row[] {
    const conditions = ['b.deleted_at IS NULL'];
    const params: unknown[] = [];
    if (status) { conditions.push('b.status = ?'); params.push(status); }
    if (partyId) { conditions.push('b.customer_id = ?'); params.push(partyId); }
    if (agreementCompanyId) { conditions.push('b.agreement_company_id = ?'); params.push(agreementCompanyId); }
    const where = conditions.join(' AND ');
    return this.raw(
      `SELECT b.id, b.description, c.name AS party, b.amount_cents, b.issue_date, b.due_date, b.status,
              b.notes, b.received_at AS settled_at, b.received_cents AS settled_cents,
              spm.name AS settle_method_name,
              b.installment_group_id, b.installment_no, b.installment_count,
              b.sale_id
       FROM receivables b LEFT JOIN customers c ON c.id = b.customer_id
            LEFT JOIN payment_methods spm ON spm.id = b.settle_payment_method_id
       WHERE ${where} ORDER BY b.due_date, b.id`,
      ...params,
    );
  }

  findDetail(id: number | string): Row | undefined {
    return this.rawOne(
      `SELECT b.id, b.description, b.customer_id AS party_id, c.name AS party,
              b.amount_cents, b.issue_date, b.due_date, b.status, b.received_at AS settled_at,
              b.received_cents AS settled_cents, b.notes, b.updated_at,
              b.settle_payment_method_id, spm.name AS settle_method_name,
              b.installment_group_id, b.installment_no, b.installment_count,
              b.sale_id
       FROM receivables b LEFT JOIN customers c ON c.id = b.customer_id
            LEFT JOIN payment_methods spm ON spm.id = b.settle_payment_method_id
       WHERE b.id = ? AND b.deleted_at IS NULL`,
      id,
    );
  }

  listBySale(saleId: number): Row[] {
    return this.raw(
      `SELECT id, description, amount_cents, due_date, status, installment_no, installment_count
       FROM receivables WHERE sale_id = ? AND deleted_at IS NULL ORDER BY installment_no, id`,
      saleId,
    );
  }

  findNextInstallment(groupId: string, nextNo: number): Row | undefined {
    return this.rawOne(
      `SELECT id FROM receivables WHERE installment_group_id = ? AND installment_no = ? AND status = 'aberta'`,
      groupId, nextNo,
    );
  }

  findNextBySale(saleId: number, nextNo: number): Row | undefined {
    return this.rawOne(
      `SELECT id FROM receivables WHERE sale_id = ? AND installment_no = ? AND status = 'aberta'`,
      saleId, nextNo,
    );
  }

  settle(id: number | string, status: string, dateCol: string, centsCol: string, paidCents: number, paymentMethodId: number | null): void {
    this.rawRun(
      `UPDATE receivables SET status = ?, ${dateCol} = datetime('now'), ${centsCol} = ?, settle_payment_method_id = ?, updated_at = datetime('now') WHERE id = ?`,
      status, paidCents, paymentMethodId, id,
    );
  }

  cancelBySale(saleId: number): void {
    this.rawRun(
      `UPDATE receivables SET status = 'cancelada', updated_at = datetime('now') WHERE sale_id = ? AND status = 'aberta'`,
      saleId,
    );
  }

  findByAgreementAndPeriod(companyId: number, periodKey: string): Row | undefined {
    return this.rawOne(
      'SELECT id FROM receivables WHERE agreement_company_id = ? AND period_key = ? AND deleted_at IS NULL',
      companyId, periodKey,
    );
  }

  findOpenByDueDate(limitDate: string): Row[] {
    return this.raw(
      `SELECT id, description, amount_cents, due_date FROM receivables
       WHERE status = 'aberta' AND deleted_at IS NULL AND due_date <= ? ORDER BY due_date LIMIT 20`,
      limitDate,
    );
  }

  findSaleReceivables(saleId: number): { id: number; status: string }[] {
    return this.raw(
      'SELECT id, status FROM receivables WHERE sale_id = ? AND deleted_at IS NULL',
      saleId,
    ) as { id: number; status: string }[];
  }
}

