export class AgreementCompanyRepository extends BaseRepository {
  constructor() {
    super('agreement_companies');
  }
}

export const agreementCompanyRepository = new AgreementCompanyRepository();

export class AgreementChargeRepository extends BaseRepository {
  constructor() {
    super('agreement_charges');
  }

  findBySale(saleId: number): Row | undefined {
    return this.rawOne(
      'SELECT id, invoiced_at FROM agreement_charges WHERE sale_id = ? AND deleted_at IS NULL',
      saleId,
    );
  }

  pendingTotal(companyId: number): number {
    const row = this.rawOne(
      `SELECT COALESCE(SUM(amount_cents), 0) AS total FROM agreement_charges
       WHERE agreement_company_id = ? AND invoiced_at IS NULL AND deleted_at IS NULL`,
      companyId,
    ) as { total: number };
    return row.total;
  }

  invoiceAll(companyId: number, receivableId: number): void {
    this.rawRun(
      `UPDATE agreement_charges SET invoiced_at = datetime('now'), receivable_id = ?, updated_at = datetime('now')
       WHERE agreement_company_id = ? AND invoiced_at IS NULL AND deleted_at IS NULL`,
      receivableId, companyId,
    );
  }
}

export const agreementChargeRepository = new AgreementChargeRepository();

import type { Request } from 'express';
import { companiesDueForInvoice, generateInvoice } from './agreements';

/** Requisição sintética para ações disparadas pelo sistema (sem operador humano). */
const systemReq = {} as Request;

function runCheck(): void {
  for (const company of companiesDueForInvoice()) {
    const result = generateInvoice(systemReq, company.id);
    if (result.ok) {
      console.log(`[convenio] fatura gerada automaticamente: ${company.name} — ${result.amountCents} centavos.`);
    } else {
      console.error(`[convenio] falha ao gerar fatura automática de ${company.name}: ${result.error}`);
    }
  }
}

/**
 * Agendador do fechamento mensal de convênio: como o Katsu não fica sempre aberto,
 * não há garantia de rodar exatamente no dia de fechamento — por isso verifica no
 * boot (catch-up de qualquer fechamento perdido) e periodicamente depois.
 */
export function startAgreementScheduler(): NodeJS.Timeout {
  runCheck();
  const timer = setInterval(runCheck, 30 * 60_000);
  timer.unref();
  return timer;
}

import { BaseRepository, type Row } from '../../../core/database/repository';

export class PaymentMethodRepository extends BaseRepository {
  constructor() {
    super('payment_methods');
  }

  listActive(): Row[] {
    return this.raw(
      'SELECT id, name, type, fee_bps FROM payment_methods WHERE active = 1 AND deleted_at IS NULL ORDER BY sort, name',
    );
  }

  listActiveLite(): Row[] {
    return this.raw(
      "SELECT id, name, type FROM payment_methods WHERE active = 1 AND deleted_at IS NULL AND type != 'prazo' ORDER BY sort, name",
    );
  }

  listAll(): Row[] {
    return this.raw(
      'SELECT id, name, type, fee_bps, active, sort FROM payment_methods WHERE deleted_at IS NULL ORDER BY sort, name',
    );
  }

  findActive(id: number): Row | undefined {
    return this.rawOne(
      'SELECT id, name, type, fee_bps FROM payment_methods WHERE id = ? AND active = 1 AND deleted_at IS NULL',
      id,
    );
  }

  findByType(type: string): Row | undefined {
    return this.rawOne(
      'SELECT id, name, type, fee_bps FROM payment_methods WHERE type = ? AND active = 1 AND deleted_at IS NULL ORDER BY sort, name LIMIT 1',
      type,
    );
  }
}

